function toggleDarkLight() {
  const current = localStorage.getItem('studioDisplayMode') || 'dark';
  const next = current === 'dark' ? 'light' : 'dark';
  setDisplayMode(next);
  const btn = document.getElementById('dark-toggle-btn');
  if(btn) { var ic=btn.querySelector('i'); if(ic) ic.className=next==='dark'?'fa-solid fa-moon':'fa-solid fa-sun'; }
}

function setDisplayMode(mode) {
  document.body.classList.toggle('light-mode', mode === 'light');
  document.documentElement.classList.toggle('light-mode', mode === 'light');
  localStorage.setItem('studioDisplayMode', mode);

  // ── Fix: Update inline CSS variables + background that anti-flash script sets ──
  if(mode === 'light') {
    document.documentElement.style.setProperty('--bg',      '#f0f2f8');
    document.documentElement.style.setProperty('--surface', '#ffffff');
    document.documentElement.style.setProperty('--surface2','#f5f6fb');
    document.documentElement.style.setProperty('--surface3','#eceef5');
    document.documentElement.style.setProperty('--border',  '#d8dae8');
    document.documentElement.style.setProperty('--text',    '#1a1a2e');
    document.documentElement.style.setProperty('--text2',   '#5a5a7a');
    document.documentElement.style.setProperty('--text3',   '#9090b0');
    document.documentElement.style.background = '#f0f2f8';
    document.body.style.background = '#f0f2f8';
    document.body.style.color = '#1a1a2e';
  } else {
    document.documentElement.style.setProperty('--bg',      '#0a0a0f');
    document.documentElement.style.setProperty('--surface', '#111118');
    document.documentElement.style.setProperty('--surface2','#16161f');
    document.documentElement.style.setProperty('--surface3','#1c1c28');
    document.documentElement.style.setProperty('--border',  '#2a2a3a');
    document.documentElement.style.setProperty('--text',    '#e8e8f0');
    document.documentElement.style.setProperty('--text2',   '#9090a8');
    document.documentElement.style.setProperty('--text3',   '#5a5a70');
    document.documentElement.style.background = '#0a0a0f';
    document.body.style.background = '#0a0a0f';
    document.body.style.color = '#e8e8f0';
  }

  const btnDark  = document.getElementById('btn-dark-mode');
  const btnLight = document.getElementById('btn-light-mode');
  if(btnDark && btnLight) {
    btnDark.className  = mode === 'dark'  ? 'btn btn-primary' : 'btn btn-ghost';
    btnLight.className = mode === 'light' ? 'btn btn-primary' : 'btn btn-ghost';
  }
  const toggleBtn = document.getElementById('dark-toggle-btn');
  if(toggleBtn){ var tic=toggleBtn.querySelector('i'); if(tic) tic.className=mode==='dark'?'fa-solid fa-moon':'fa-solid fa-sun'; var bi=document.querySelector('#bnm-dark-icon i'); if(bi) bi.className=mode==='dark'?'fa-solid fa-moon':'fa-solid fa-sun'; }
  // Sync to cloud
  if(typeof S !== 'undefined' && S){
    if(!S.settings) S.settings={};
    S.settings.displayMode = mode;
    if(typeof lsSave==='function') lsSave();
    clearTimeout(window._modeCloudTimer);
    if(typeof cloudSaveNow==='function') cloudSaveNow(S);
  }
  // Force recreate styled elements so they pick up new variables
  var _staleEls = ['_toast','_autosave-dot','sync-indicator','mini-notif'];
  _staleEls.forEach(function(id){ var e=document.getElementById(id); if(e) e.remove(); });
}

function setThemeColor(color) {
  document.documentElement.style.setProperty('--accent', color);
  localStorage.setItem('studioAccentColor', color);
  // update swatches
  document.querySelectorAll('.theme-swatch').forEach(s => {
    s.classList.toggle('active', s.dataset.color === color);
  });
  const picker = document.getElementById('custom-accent-picker');
  if(picker) picker.value = color;
  // Sync to cloud via S.settings
  if(typeof S !== 'undefined' && S){
    if(!S.settings) S.settings={};
    S.settings.accentColor = color;
    if(typeof lsSave === 'function') lsSave();
    if(typeof cloudSave === 'function') clearTimeout(window._themeCloudTimer);
    if(typeof cloudSaveNow==='function') cloudSaveNow(S);
  }
}

