function _getFeatSettings(){try{return JSON.parse(localStorage.getItem('_featSettings')||'{}');}catch(e){return {};}}
function _saveFeatSettings(){
  var settings={
    alert24:document.getElementById('feat-alert-24')?.checked,
    alert48:document.getElementById('feat-alert-48')?.checked,
    challengeEnabled:document.getElementById('feat-challenge-enabled')?.checked,
    silentDays:+(document.getElementById('feat-silent-days')?.value)||30,
    commitmentThreshold:+(document.getElementById('feat-commitment-threshold')?.value)||70,
  };
  localStorage.setItem('_featSettings',JSON.stringify(settings));
  if(typeof showMiniNotif==='function') showMiniNotif('<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم حفظ إعدادات الميزات');
  renderNewWidgets&&renderNewWidgets();
}
function _saveFeatCapacity(){
  var val=+(document.getElementById('feat-capacity')?.value)||10;
  if(!S.settings)S.settings={};
  S.settings.monthlyCapacity=val;
  lsSave();cloudSave(S);
  if(typeof showMiniNotif==='function') showMiniNotif('<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> طاقة العمل: '+val+' مهمة');
}
function _getLastSeenUpdate(){return localStorage.getItem('_lastSeenUpdate')||'';}
function _markUpdatesSeen(){
  localStorage.setItem('_lastSeenUpdate',_ALL_UPDATES[0]?.id||'');
  var badge=document.getElementById('stab-features-badge');
  if(badge)badge.style.display='none';
  var lbl=document.getElementById('feat-last-seen-label');
  if(lbl)lbl.innerHTML='<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> كل التحديثات مقروءة';
  _renderFeaturesPanel();
}

function _renderFeaturesPanel(){
  // Load saved settings
  var fs=_getFeatSettings();
  var a24=document.getElementById('feat-alert-24');if(a24)a24.checked=fs.alert24!==false;
  var a48=document.getElementById('feat-alert-48');if(a48)a48.checked=fs.alert48!==false;
  var chk=document.getElementById('feat-challenge-enabled');if(chk)chk.checked=fs.challengeEnabled!==false;
  var sd=document.getElementById('feat-silent-days');if(sd)sd.value=fs.silentDays||30;
  var ct=document.getElementById('feat-commitment-threshold');if(ct)ct.value=fs.commitmentThreshold||70;
  var cap=document.getElementById('feat-capacity');if(cap)cap.value=S.settings?.monthlyCapacity||10;

  // Render settings grid
  var grid=document.getElementById('feat-settings-grid');
  if(grid){
    var settingCards=[
      {emoji:'<i class="fa-solid fa-coins"></i>',color:'var(--accent2)',title:'طاقة العمل',desc:'كم مهمة نشطة تستطيع إدارتها؟',inputId:'feat-capacity',inputType:'number',inputExtra:'min="1" max="50"',save:'_saveFeatCapacity()',go:"showPage('dashboard');switchSettingsTab('general')",goLabel:'الداشبورد'},
      {emoji:'<i class="fa-solid fa-alarm-clock"></i>',color:'var(--accent4)',title:'تنبيه مواعيد التسليم',desc:'تنبيه مسبق 24/48 ساعة قبل الموعد',checkId:'feat-alert-24',checkLabel:'24 ساعة',checkId2:'feat-alert-48',checkLabel2:'48 ساعة',save:'_saveFeatSettings()',go:"showPage('tasks');switchSettingsTab('general')",goLabel:'المهام'},
      {emoji:'<i class="fa-solid fa-trophy"></i>',color:'var(--accent2)',title:'تحدي الأسبوع',desc:'تحديات أسبوعية تلقائية في الداشبورد',checkId:'feat-challenge-enabled',checkLabel:'تفعيل التحدي',save:'_saveFeatSettings()',go:"showPage('dashboard');switchSettingsTab('general')",goLabel:'الداشبورد'},
      {emoji:'<i class="fa-solid fa-bell-slash"></i>',color:'var(--accent)',title:'تنبيه العميل الهادي',desc:'تنبيه لو عميل لم يتواصل منذ X يوم',inputId:'feat-silent-days',inputType:'number',inputExtra:'min="7" max="180"',save:'_saveFeatSettings()',go:"showPage('clients');switchSettingsTab('general')",goLabel:'العملاء'},
      {emoji:'<i class="fa-solid fa-bullseye"></i>',color:'var(--accent3)',title:'عتبة مؤشر الالتزام',desc:'تحذير لو الالتزام أقل من X%',inputId:'feat-commitment-threshold',inputType:'number',inputExtra:'min="50" max="100"',save:'_saveFeatSettings()',go:"showPage('dashboard');switchSettingsTab('general')",goLabel:'الداشبورد'},
      {emoji:'<i class="fa-solid fa-dna"></i>',color:'var(--accent2)',title:'DNA العميل + تقارير',desc:'شخصية وسجل دفع وتقارير لكل عميل',save:null,go:"showPage('clients');switchSettingsTab('general')",goLabel:'قاعدة العملاء'},
    ];
    grid.innerHTML=settingCards.map(c=>`
      <div style="background:var(--surface2);border-radius:10px;padding:14px">
        <div style="font-size:12px;font-weight:800;color:${c.color};margin-bottom:5px">${c.emoji} ${c.title}</div>
        <div style="font-size:11px;color:var(--text3);margin-bottom:8px">${c.desc}</div>
        ${c.inputId?`<div style="display:flex;gap:5px;align-items:center;margin-bottom:8px">
          <input id="${c.inputId}" type="${c.inputType}" ${c.inputExtra||''} class="form-input" style="width:70px" placeholder="">
          <span style="font-size:11px;color:var(--text3)">${c.inputType==='number'&&(c.inputId==='feat-commitment-threshold')?'%':c.inputId==='feat-silent-days'?'يوم':''}</span>
        </div>`:''}
        ${c.checkId?`<div style="margin-bottom:8px"><label style="display:flex;align-items:center;gap:5px;font-size:12px;cursor:pointer"><input type="checkbox" id="${c.checkId}" style="accent-color:var(--accent)" onchange="${c.save}"> ${c.checkLabel}</label>${c.checkId2?`<label style="display:flex;align-items:center;gap:5px;font-size:12px;cursor:pointer;margin-top:4px"><input type="checkbox" id="${c.checkId2}" style="accent-color:var(--accent2)" onchange="${c.save}"> ${c.checkLabel2}</label>`:''}</div>`:''}
        <div style="display:flex;gap:5px;flex-wrap:wrap">
          ${c.save?`<button class="btn btn-primary btn-sm" onclick="${c.save}" data-i18n="btn_save"><i class="fa-solid fa-floppy-disk" style="margin-left:4px"></i> حفظ</button>`:''}
          <button class="btn btn-ghost btn-sm" onclick="${c.go}">${c.goLabel} →</button>
        </div>
      </div>`).join('');
    // Re-apply saved values after rendering
    var fs2=_getFeatSettings();
    var el;
    el=document.getElementById('feat-alert-24');if(el)el.checked=fs2.alert24!==false;
    el=document.getElementById('feat-alert-48');if(el)el.checked=fs2.alert48!==false;
    el=document.getElementById('feat-challenge-enabled');if(el)el.checked=fs2.challengeEnabled!==false;
    el=document.getElementById('feat-silent-days');if(el)el.value=fs2.silentDays||30;
    el=document.getElementById('feat-commitment-threshold');if(el)el.value=fs2.commitmentThreshold||70;
    el=document.getElementById('feat-capacity');if(el)el.value=S.settings?.monthlyCapacity||10;
  }

  // ── Admin Updates (dynamic from Supabase/studio_data platform) ──
  var adminUpdatesEl = document.getElementById('admin-updates-list');
  if(adminUpdatesEl) _renderAdminUpdates(adminUpdatesEl);

  // Last seen label & badge
  var lastSeen=_getLastSeenUpdate();
  var lbl=document.getElementById('feat-last-seen-label');
  var hasNew=lastSeen!==(_ALL_UPDATES[0]?.id||'');
  if(lbl)lbl.innerHTML=hasNew?
    '<button class="btn btn-primary btn-sm" onclick="_markUpdatesSeen()"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تحديد الكل كمقروء</button>':
    '<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> كل التحديثات مقروءة';

  // Render updates list
  var el=document.getElementById('feat-updates-list');if(!el)return;
  var lastIdx=lastSeen?_ALL_UPDATES.findIndex(u=>u.id===lastSeen):-1;
  el.innerHTML=_ALL_UPDATES.map((u,i)=>{
    var isNew=i<lastIdx||lastSeen==='';
    return '<div style="display:flex;gap:14px;align-items:flex-start;padding:14px 0;border-bottom:1px solid var(--border)">'+
      '<div style="font-size:26px;flex-shrink:0;margin-top:2px">'+u.emoji+'</div>'+
      '<div style="flex:1;min-width:0">'+
        '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">'+
          '<div style="font-size:13px;font-weight:800">'+u.title+'</div>'+
          '<span style="font-size:9px;background:var(--surface2);padding:2px 7px;border-radius:8px;color:var(--text3)">'+u.version+'</span>'+
          (isNew?'<span style="font-size:9px;background:var(--accent4);color:#fff;padding:2px 7px;border-radius:8px;font-weight:700">🆕 جديد</span>':'')+
        '</div>'+
        '<div style="font-size:12px;color:var(--text2);margin-bottom:8px;line-height:1.6">'+u.desc+'</div>'+
        '<div style="display:flex;gap:6px;flex-wrap:wrap">'+
          '<button class="btn btn-primary btn-sm" onclick="'+u.nav+';switchSettingsTab(\'general\')">'+u.navLabel+'</button>'+
          (u.settingsId?'<span style="font-size:11px;color:var(--accent);cursor:pointer;display:flex;align-items:center;gap:3px" onclick="document.getElementById(\''+u.settingsId+'\')?.scrollIntoView({behavior:\'smooth\'})"><i class="fa-solid fa-gear"></i> إعداد</span>':'')+
        '</div>'+
      '</div>'+
    '</div>';
  }).join('');
}

// Startup: check for new updates
(function(){
  setTimeout(function(){
    var lastSeen=_getLastSeenUpdate();
    var hasNew=lastSeen!==(_ALL_UPDATES[0]?.id||'');
    if(hasNew){
      var badge=document.getElementById('stab-features-badge');
      if(badge)badge.style.display='inline-block';
      var newCount=lastSeen===''?_ALL_UPDATES.length:Math.max(0,_ALL_UPDATES.findIndex(u=>u.id===lastSeen));
      if(newCount>0&&typeof addNotification==='function'){
        addNotification('<i class="fa-solid fa-rocket"></i> '+newCount+' ميزة جديدة في السيستم — اضغط على الإعدادات > التحديثات','info');
      }
    }
  },2000);
})();

// ─── Admin-sent Updates Renderer ───
function _renderAdminUpdates(container){
  // Admin updates stored in S._platform_updates (array injected by admin into studio_data)
  var updates = (typeof S !== 'undefined' && S._platform_updates) ? S._platform_updates : [];
  // Also check localStorage for cached platform updates
  try {
    var cached = JSON.parse(localStorage.getItem('_platform_updates_cache')||'[]');
    // Merge, deduplicate by id
    cached.forEach(function(u){ if(!updates.find(function(x){ return x.id===u.id; })) updates.push(u); });
  } catch(e){}
  if(!updates.length){ container.innerHTML = ''; return; }
  // Sort by date desc
  updates = updates.slice().sort(function(a,b){ return new Date(b.date||0) - new Date(a.date||0); });
  var lastReadAdminUpdate = localStorage.getItem('_last_read_admin_update')||'';
  var newOnes = [];
  updates.forEach(function(u,i){ if(u.id !== lastReadAdminUpdate && !newOnes.includes(u.id)) newOnes.push(u.id); if(i===0) {} });
  container.innerHTML =
    '<div style="background:linear-gradient(135deg,rgba(124,111,247,.1),rgba(79,209,165,.05));border:1.5px solid var(--accent);border-radius:12px;padding:14px 16px;margin-bottom:16px">'+
    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px">'+
      '<div style="font-size:14px;font-weight:800;color:var(--accent)"><i class="fa-solid fa-bullhorn"></i> تحديثات الإدارة</div>'+
      (newOnes.length?'<span style="background:var(--accent4);color:#fff;font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px">'+newOnes.length+' جديد</span>':'')+
    '</div>'+
    updates.map(function(u){
      var isNew = newOnes.includes(u.id);
      return '<div style="padding:12px;background:var(--surface2);border-radius:10px;margin-bottom:8px;border-right:3px solid '+(isNew?'var(--accent4)':'var(--border)')+'">'+
        '<div style="display:flex;align-items:center;gap:8px;margin-bottom:5px">'+
          '<span style="font-size:18px">'+(u.emoji||'<i class="fa-solid fa-thumbtack"></i>')+'</span>'+
          '<div style="font-size:13px;font-weight:700;flex:1">'+u.title+'</div>'+
          (isNew?'<span style="background:var(--accent4);color:#fff;font-size:9px;font-weight:700;padding:2px 7px;border-radius:8px">جديد</span>':'')+
          '<span style="font-size:10px;color:var(--text3)">'+(u.date?new Date(u.date).toLocaleDateString('ar-EG'):'')+'</span>'+
        '</div>'+
        '<div style="font-size:12px;color:var(--text2);line-height:1.7">'+u.body+'</div>'+
      '</div>';
    }).join('')+
    '<button class="btn btn-ghost btn-sm" style="margin-top:4px" onclick="_markAdminUpdatesSeen()"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تحديد كمقروء</button>'+
    '</div>';
}
function _markAdminUpdatesSeen(){
  var updates = (typeof S !== 'undefined' && S._platform_updates) ? S._platform_updates : [];
  if(updates.length) localStorage.setItem('_last_read_admin_update', updates[0].id);
  var adminUpdatesEl = document.getElementById('admin-updates-list');
  if(adminUpdatesEl) _renderAdminUpdates(adminUpdatesEl);
}

// Startup: check for new admin updates
(function(){
  setTimeout(function(){
    var updates = (typeof S !== 'undefined' && S._platform_updates) ? S._platform_updates : [];
    if(!updates.length) return;
    var lastRead = localStorage.getItem('_last_read_admin_update')||'';
    var latest = updates[0];
    if(latest && latest.id !== lastRead){
      // Cache them
      try{ localStorage.setItem('_platform_updates_cache', JSON.stringify(updates.slice(0,20))); }catch(e){}
      if(typeof addNotification === 'function'){
        addNotification('<i class="fa-solid fa-bullhorn"></i> '+(latest.emoji||'')+(latest.title||'تحديث جديد من الإدارة'),'info');
      }
      var badge=document.getElementById('stab-features-badge');
      if(badge)badge.style.display='inline-block';
    }
  }, 3000);
})();


function renderClients(){
  const grid=document.getElementById('clients-grid');if(!grid)return;

  // apply filters
  const typeF   = document.getElementById('cf-type')?.value||'';
  const chanF   = document.getElementById('cf-channel')?.value||'';
  const searchF = (document.getElementById('cf-search')?.value||'').trim().toLowerCase();

  let clients = S.clients;
  if(typeF)   clients = clients.filter(c=>c.type===typeF);
  if(chanF)   clients = clients.filter(c=>c.channel===chanF);
  if(searchF) clients = clients.filter(c=>(c.name+' '+(c.notes||'')).toLowerCase().includes(searchF));

  const cnt = document.getElementById('cf-count');
  if(cnt) cnt.textContent = clients.length < S.clients.length ? `${clients.length} من ${S.clients.length}` : '';

  if(!clients.length){
    var emptyMsg = S.clients.length
      ? '<div class="empty" style="grid-column:span 3"><div class="empty-icon"><i class="fa-solid fa-magnifying-glass"></i></div>لا نتائج تطابق الفلتر</div>'
      : '<div class="empty" style="grid-column:span 3"><div class="empty-icon"><i class="fa-solid fa-circle-dot"></i></div>لم تضف عملاء بعد</div>';
    grid.innerHTML=emptyMsg;
    var listV=document.getElementById('clients-list-view'); if(listV) listV.innerHTML=emptyMsg;
    var tbodyV=document.getElementById('clients-table-body'); if(tbodyV) tbodyV.innerHTML='<tr><td colspan="7" style="text-align:center;padding:32px;color:var(--text3)">لا نتائج</td></tr>';
    return;
  }
  const cTasks=n=>S.tasks.filter(t=>t.client===n).length;
  const cInc=n=>S.transactions.filter(t=>t.type==='income'&&t.source===n).reduce((s,t)=>s+t.amount,0);
  const cThisMonth=n=>{const now=new Date();const ms=now.getFullYear()+'-'+String(now.getMonth()+1).padStart(2,'0');return S.tasks.filter(t=>t.client===n&&((t.isoDate||'').startsWith(ms)||(t.doneAt||'').startsWith(ms))).length;};
  
  // Grid view (existing cards)
  grid.innerHTML=clients.map(c=>`
    <div class="client-card" onclick="openClientProfile(${c.id})" style="cursor:pointer">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div class="client-avatar" style="background:${c.color}22;color:${c.color}">${c.name[0]}</div>
        <div style="display:flex;gap:4px" onclick="event.stopPropagation()">
          <button class="btn btn-ghost btn-sm" title="إعدادات / تعديل" onclick="openClientModal(${c.id})"><i class="fa-solid fa-gear"></i>️</button>
          <button class="btn btn-ghost btn-sm" title="بوابة العميل" onclick="openClientPortal(${c.id})"><i class="fa-solid fa-link"></i></button>
          <button class="btn btn-danger btn-sm" onclick="delClient(${c.id})"><i class="fa-solid fa-trash"></i></button>
        </div>
      </div>
      <div style="font-size:15px;font-weight:700">${c.name}${(()=>{const subs=S.clients.filter(sc=>String(sc.parentClientId)===String(c.id));return subs.length?` <span style="font-size:10px;background:rgba(124,111,247,.15);color:var(--accent);padding:1px 7px;border-radius:8px;font-weight:600"><i class="fa-solid fa-building"></i> ${subs.length} فرع</span>`:'';})()}</div>
      <div style="font-size:12px;color:var(--text2);margin-top:2px;display:flex;gap:6px;flex-wrap:wrap;align-items:center">
        <span>${c.type} · ${c.channel}${c.field?' · '+c.field:''}</span>
        ${c.workType==='fulltime'?'<span class="jtype-badge jtype-fulltime"><i class="fa-solid fa-building"></i> دوام</span>':c.workType==='parttime'?'<span class="jtype-badge jtype-parttime"><i class="fa-solid fa-alarm-clock"></i> بارت تايم</span>':c.workType==='sub'?(()=>{const par=S.clients.find(p=>String(p.id)===String(c.parentClientId));return `<span class="jtype-badge" style="background:rgba(79,209,165,.12);color:var(--accent3)"><i class="fa-solid fa-link"></i> تابع${par?' لـ '+par.name:''}</span>`;})():'<span class="jtype-badge jtype-freelance"><i class="fa-solid fa-bullseye"></i> فري لانس</span>'}
      </div>
      ${c.salary?`<div style="font-size:12px;color:var(--accent3);margin-top:4px;font-weight:700"><i class="fa-solid fa-coins"></i> ${c.salary.toLocaleString()} ج/شهر · يوم ${c.salaryDay}</div>`:''}
      ${c.phone?`<div style="font-size:12px;color:var(--text3);margin-top:6px;display:flex;align-items:center;gap:8px"><i class="fa-solid fa-phone"></i> ${c.phone}<a href="https://wa.me/${c.phone.replace(/[^\d]/g,'')}" target="_blank" onclick="event.stopPropagation()" style="display:inline-flex;align-items:center;gap:4px;background:#25D366;color:#fff;font-size:11px;font-weight:700;padding:2px 8px;border-radius:12px;text-decoration:none"><i class="fa-solid fa-comments"></i> واتساب</a></div>`:''}
      ${c.email?`<div style="font-size:12px;color:var(--text3)"><i class="fa-solid fa-envelope"></i> ${c.email}</div>`:''}
      ${c.notes?`<div style="font-size:12px;color:var(--text3);margin-top:6px;font-style:italic">${c.notes.slice(0,60)}${c.notes.length>60?'...':''}</div>`:''}
      <div style="display:flex;gap:16px;margin-top:12px">
        <div><div style="font-size:16px;font-weight:700;color:${c.color}">${cTasks(c.name)}</div><div style="font-size:11px;color:var(--text3)">مشاريع</div></div>
        <div><div style="font-size:16px;font-weight:700;color:var(--accent2)">${cThisMonth(c.name)}</div><div style="font-size:11px;color:var(--text3)">هذا الشهر</div></div>
        ${(()=>{const revs=(S.reviews||[]).filter(r=>String(r.client_id)===String(c.id)||r.client_name===c.name);if(!revs.length)return'';const avg=(revs.reduce((s,r)=>s+(+r.stars||0),0)/revs.length).toFixed(1);return`<div><div style="font-size:16px;font-weight:700;color:#f7c948">⭐ ${avg}</div><div style="font-size:11px;color:var(--text3)">${revs.length} تقييم</div></div>`;})()}
      </div>
    </div>`).join('');

  // List view
  var listV=document.getElementById('clients-list-view');
  if(listV){
    listV.innerHTML='<div style="display:flex;flex-direction:column;gap:8px">'+clients.map(c=>{
      var acc2=c.color||'var(--accent)';
      var clientTasks=S.tasks.filter(t=>t.client===c.name);
      var hasTasksToShow=clientTasks.length>0;
      return '<div class="card" style="padding:0;border-right:3px solid '+acc2+';overflow:hidden">'
        +'<div style="display:flex;align-items:center;gap:12px;padding:14px 18px;cursor:pointer" onclick="openClientProfile('+c.id+')">'
          +(hasTasksToShow?'<button onclick="event.stopPropagation();_toggleClientTasks('+c.id+')" style="background:none;border:none;cursor:pointer;color:var(--accent);font-size:12px;padding:4px;flex-shrink:0;transition:transform .2s" id="_cl-arrow-'+c.id+'"><i class="fa-solid fa-chevron-down"></i></button>':'<span style="width:28px"></span>')
          +'<div style="width:40px;height:40px;border-radius:50%;background:'+acc2+'22;color:'+acc2+';font-size:16px;font-weight:900;display:flex;align-items:center;justify-content:center;flex-shrink:0">'+c.name[0]+'</div>'
          +'<div style="flex:1;min-width:0">'
            +'<div style="font-size:14px;font-weight:800">'+escapeHtml(c.name)+'</div>'
            +'<div style="font-size:11px;color:var(--text3)">'+(c.type||'')+' · '+(c.channel||'')+(c.phone?' · '+c.phone:'')+'</div>'
          +'</div>'
          +'<div style="display:flex;gap:12px;align-items:center;font-size:12px;color:var(--text3)">'
            +'<span><strong style="color:'+acc2+'">'+cTasks(c.name)+'</strong> مشروع</span>'
            +'<span><strong style="color:var(--accent2)">'+cThisMonth(c.name)+'</strong> هذا الشهر</span>'
          +'</div>'
          +'<div style="display:flex;gap:4px" onclick="event.stopPropagation()">'
            +'<button class="btn btn-ghost btn-sm" onclick="openClientModal('+c.id+')"><i class="fa-solid fa-pen"></i></button>'
            +'<button class="btn btn-ghost btn-sm" onclick="openClientPortal('+c.id+')"><i class="fa-solid fa-link"></i></button>'
          +'</div>'
        +'</div>'
        +(hasTasksToShow?'<div id="_cl-tasks-'+c.id+'" style="display:none;padding:0 18px 14px;background:var(--surface2);border-top:1px solid var(--border)">'
          +'<div style="font-size:11px;font-weight:800;color:var(--text3);padding:10px 0 8px"><i class="fa-solid fa-list-check" style="color:var(--accent);margin-left:4px"></i> مشاريع العميل ('+clientTasks.length+')</div>'
          +clientTasks.slice(0,10).map(function(t){
            var isDone=t.done||t.status==='done';
            var stColor=isDone?'var(--accent3)':t.status==='progress'?'var(--accent2)':t.status==='review'?'var(--accent)':'var(--text3)';
            var stLabel=isDone?'مكتمل':t.status==='progress'?'جاري':t.status==='review'?'مراجعة':t.status==='paused'?'موقوف':'جديد';
            return '<div style="display:flex;align-items:center;gap:8px;padding:7px 0;border-bottom:1px solid var(--border);font-size:12px;cursor:pointer" onclick="event.stopPropagation();openTaskDetail('+t.id+')">'
              +'<div style="width:8px;height:8px;border-radius:50%;background:'+stColor+';flex-shrink:0"></div>'
              +'<div style="flex:1;'+(isDone?'text-decoration:line-through;color:var(--text3)':'')+'">'+escapeHtml(t.title)+'</div>'
              +'<span style="font-size:10px;font-weight:700;color:'+stColor+';background:'+stColor+'18;padding:2px 7px;border-radius:8px">'+stLabel+'</span>'
              +(t.value?'<span style="font-size:10px;color:var(--accent3);font-weight:700">'+t.value.toLocaleString()+' ج</span>':'')
            +'</div>';
          }).join('')
          +(clientTasks.length>10?'<div style="font-size:11px;color:var(--accent);text-align:center;padding:8px;font-weight:700;cursor:pointer" onclick="event.stopPropagation();openClientProfile('+c.id+')">+ '+String(clientTasks.length-10)+' مشروع آخر ←</div>':'')
        +'</div>':'')
      +'</div>';
    }).join('')+'</div>';
  }

  // Table view
  var tbodyV=document.getElementById('clients-table-body');
  if(tbodyV){
    tbodyV.innerHTML=clients.map(function(c,idx){
      var bg=idx%2===0?'var(--surface)':'var(--surface2)';
      return '<tr style="background:'+bg+';cursor:pointer" onclick="openClientProfile('+c.id+')">'
        +'<td style="padding:10px 14px;border-bottom:1px solid var(--border)"><div style="display:flex;align-items:center;gap:8px"><div style="width:30px;height:30px;border-radius:50%;background:'+(c.color||'var(--accent)')+'22;color:'+(c.color||'var(--accent)')+';font-size:12px;font-weight:900;display:flex;align-items:center;justify-content:center;flex-shrink:0">'+c.name[0]+'</div><div style="font-weight:700">'+escapeHtml(c.name)+'</div></div></td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border);font-size:11px;color:var(--text3)">'+(c.type||'—')+'</td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border);font-size:11px;color:var(--text3)">'+(c.channel||'—')+'</td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border);font-size:11px;color:var(--text3)">'+(c.phone||'—')+'</td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border);font-weight:700;color:'+(c.color||'var(--accent)')+'">'+cTasks(c.name)+'</td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border);font-weight:700;color:var(--accent2)">'+cThisMonth(c.name)+'</td>'
        +'<td style="padding:10px 8px;text-align:center;border-bottom:1px solid var(--border)" onclick="event.stopPropagation()"><div style="display:flex;gap:4px;justify-content:center"><button class="btn btn-ghost btn-sm" style="padding:3px 7px" onclick="openClientModal('+c.id+')"><i class="fa-solid fa-pen"></i></button><button class="btn btn-ghost btn-sm" style="padding:3px 7px" onclick="openClientPortal('+c.id+')"><i class="fa-solid fa-link"></i></button><button class="btn btn-danger btn-sm" style="padding:3px 7px" onclick="delClient('+c.id+')"><i class="fa-solid fa-trash"></i></button></div></td>'
      +'</tr>';
    }).join('');
  }
}

// Client view switching
var _clientViewMode = localStorage.getItem('studioClientView') || 'grid';

// Toggle client tasks expandable section in list view
function _toggleClientTasks(clientId){
  var row = document.getElementById('_cl-tasks-'+clientId);
  var arrow = document.getElementById('_cl-arrow-'+clientId);
  if(!row) return;
  var isOpen = row.style.display !== 'none';
  row.style.display = isOpen ? 'none' : 'block';
  if(arrow) arrow.style.transform = isOpen ? '' : 'rotate(180deg)';
}
function _switchClientView(mode){
  _clientViewMode = mode;
  localStorage.setItem('studioClientView', mode);
  var gridEl = document.getElementById('clients-grid');
  var listEl = document.getElementById('clients-list-view');
  var tableEl = document.getElementById('clients-table-view');
  var gb=document.getElementById('cv-grid-btn'), lb=document.getElementById('cv-list-btn'), tb=document.getElementById('cv-table-btn');
  [gb,lb,tb].forEach(function(b){if(b){b.style.background='transparent';b.style.color='var(--text3)';}});
  if(gridEl) gridEl.style.display=mode==='grid'?'':'none';
  if(listEl) listEl.style.display=mode==='list'?'':'none';
  if(tableEl) tableEl.style.display=mode==='table'?'':'none';
  var activeBtn=mode==='grid'?gb:mode==='list'?lb:tb;
  if(activeBtn){activeBtn.style.background='var(--accent)';activeBtn.style.color='#fff';}
  renderClients();
}
// Apply saved view on first render
document.addEventListener('DOMContentLoaded',function(){
  setTimeout(function(){ if(_clientViewMode!=='grid') _switchClientView(_clientViewMode); },500);
});

// ============================================================
// FINANCE
// ============================================================
function onIncomeTaskLink(){
  const taskSel = document.getElementById('in-linked-task');
  const srcEl   = document.getElementById('in-source');
  if(!taskSel||!srcEl) return;
  const taskId = +taskSel.value;
  if(taskId){
    const t = S.tasks.find(x=>x.id===taskId);
    if(t && !srcEl.value) srcEl.value = t.client||'';
    const amtEl = document.getElementById('in-amount');
    if(t && amtEl && !amtEl.value) amtEl.value = t.value||'';
  }
}

function onIncomeProjectLink(){
  const projSel = document.getElementById('in-linked-project');
  if(!projSel || !projSel.value) return;
  const proj = (S.projects||[]).find(p => String(p.id) === String(projSel.value));
  if(!proj) return;
  // Auto-fill desc if empty
  const descEl = document.getElementById('in-desc');
  if(descEl && !descEl.value) descEl.value = 'دفعة مشروع: ' + proj.name;
}

function _fillOpenIncomeProject(projId) {
  // Call this when opening income modal from project page
  const projSel = document.getElementById('in-linked-project');
  if(!projSel) return;
  // Make sure all projects are loaded
  projSel.innerHTML = '<option value="">— لا يوجد مشروع —</option>';
  (S.projects||[]).forEach(p => {
    const opt = document.createElement('option');
    opt.value = p.id;
    opt.textContent = p.name;
    projSel.appendChild(opt);
  });
  if(projId) projSel.value = String(projId);
}
function openIncomeModal(id, prefillTaskId){
  document.getElementById('income-ttl').innerHTML=id?'<i class="fa-solid fa-coins"></i> تعديل دخل':'<i class="fa-solid fa-coins"></i> تسجيل دخل';
  document.getElementById('income-eid').value=id||'';
  // Populate clients dropdown (replaces datalist)
  fillIncomeClientDropdown();
  // Populate payment methods from custom accounts
  fillPayMethodDropdowns();
  if(id){const t=S.transactions.find(t=>t.id===id);if(t){
    document.getElementById('in-amount').value=t.amount;
    // Set client in dropdown
    const srcSel = document.getElementById('in-source');
    if(srcSel) {
      if([...srcSel.options].some(o=>o.value===t.source)) srcSel.value=t.source||'';
      else srcSel.value='';
    }
    document.getElementById('in-desc').value=t.desc||'';
    document.getElementById('in-date').value=t.isoDate||'';
    // After setting client, filter projects
    if(t.source) onIncomeClientChange(t.source);
    const taskSel = document.getElementById('in-linked-task');
    if(taskSel) setTimeout(()=>{ taskSel.value=t.linkedTaskId||''; }, 50);
    setTimeout(()=>{ _fillOpenIncomeProject(t.project_id||''); }, 60);
    const ptEl=document.getElementById('in-payment-type'); if(ptEl) ptEl.value=t.paymentType||'full';
    const pmEl=document.getElementById('in-pay-method');  if(pmEl) pmEl.value=t.payMethod||'cash';
  }}
  else{
    ['in-amount','in-desc'].forEach(f=>{const e=document.getElementById(f);if(e)e.value='';});
    const srcSel=document.getElementById('in-source'); if(srcSel) srcSel.value='';
    document.getElementById('in-date').value=new Date().toISOString().split('T')[0];
    // If prefillTaskId, find client and preselect
    if(prefillTaskId){
      const task=S.tasks.find(t=>t.id==prefillTaskId);
      if(task&&task.client){
        setTimeout(()=>{
          const srcSel=document.getElementById('in-source');
          if(srcSel) srcSel.value=task.client;
          onIncomeClientChange(task.client);
          setTimeout(()=>{
            const taskSel=document.getElementById('in-linked-task');
            if(taskSel) taskSel.value=prefillTaskId;
          },60);
        },30);
      }
    }
    const ptEl=document.getElementById('in-payment-type'); if(ptEl) ptEl.value='full';
    const pmEl=document.getElementById('in-pay-method');  if(pmEl) pmEl.value='cash';
    // Fill projects dropdown for new transaction
    setTimeout(()=>{ _fillOpenIncomeProject(''); }, 20);
  }
  openM('modal-income');
}
function openExpenseModal(id){
  document.getElementById('expense-ttl').innerHTML=id?'<i class="fa-solid fa-money-bill-wave"></i> تعديل مصروف':'<i class="fa-solid fa-money-bill-wave"></i> تسجيل مصروف';
  document.getElementById('expense-eid').value=id||'';
  fillPayMethodDropdowns();
  if(id){const t=S.transactions.find(t=>t.id===id);if(t){
    document.getElementById('ex-amount').value=t.amount;
    document.getElementById('ex-desc').value=t.desc||'';
    document.getElementById('ex-date').value=t.isoDate||'';
    const catEl=document.getElementById('ex-cat'); if(catEl) catEl.value=t.expCat||t.source||'أخرى';
    const pmEl=document.getElementById('ex-pay-method'); if(pmEl) pmEl.value=t.payMethod||'cash';
  }}
  else{
    ['ex-amount','ex-desc'].forEach(f=>{const e=document.getElementById(f);if(e)e.value='';});
    document.getElementById('ex-date').value=new Date().toISOString().split('T')[0];
    const pmEl=document.getElementById('ex-pay-method'); if(pmEl) pmEl.value='cash';
  }
  openM('modal-expense');
}
function saveTrans(type){
  const isInc=type==='income';
  const amount=+(isInc?v('in-amount'):v('ex-amount'));
  if(!amount)return alert('أدخل المبلغ');
  const eid=v(isInc?'income-eid':'expense-eid');
  const rawDate = isInc ? v('in-date') : v('ex-date');
  const isoDate = rawDate || new Date().toISOString().split('T')[0];
  const source = isInc ? v('in-source') : (v('ex-cat')||'أخرى');
  const linkedTaskId  = isInc ? (+(document.getElementById('in-linked-task')?.value)||null) : null;
  const linkedProjId  = isInc ? (document.getElementById('in-linked-project')?.value||null) : null;
  const linkedProjObj = linkedProjId ? (S.projects||[]).find(p=>String(p.id)===String(linkedProjId)) : null;
  const paymentType  = isInc ? (document.getElementById('in-payment-type')?.value||'full') : null;
  const payMethod    = isInc ? (document.getElementById('in-pay-method')?.value||'cash') : (document.getElementById('ex-pay-method')?.value||'cash');
  const expCat       = !isInc ? (v('ex-cat')||'أخرى') : null;
  const expImpact    = !isInc ? (document.querySelector('input[name="ex-profit-impact"]:checked')?.value||'work') : null;
  // Auto-fill source from linked task
  let finalSource = source;
  if(isInc && linkedTaskId && !source){
    const lt = S.tasks.find(t=>t.id===linkedTaskId);
    if(lt) finalSource = lt.client||lt.title;
  }
  const incRcpt = isInc ? (window._incReceiptData||null) : null;
  const isLoanTrans = isInc && paymentType==='loan_received';
  const d={type,amount,source:finalSource,desc:v(isInc?'in-desc':'ex-desc'),
    date:new Date(isoDate+'T00:00:00').toLocaleDateString('ar-EG'), isoDate,
    payMethod,
    ...(linkedTaskId  ? {linkedTaskId}  : {}),
    ...(linkedProjId  ? {project_id: String(linkedProjId), project_name: linkedProjObj?.name||''} : {}),
    ...(paymentType   ? {paymentType}   : {}),
    ...(expCat       ? {expCat}       : {}),
    ...(expImpact    ? {expImpact}    : {}),
    ...(incRcpt      ? {receiptImage:incRcpt} : {}),
    ...(isLoanTrans  ? {isLoan:true}  : {})};
  if(eid){const i=S.transactions.findIndex(t=>t.id==eid);if(i>-1){d.id=+eid;if(!incRcpt&&S.transactions[i].receiptImage)d.receiptImage=S.transactions[i].receiptImage;S.transactions[i]=d;}}
  else{d.id=Date.now();S.transactions.push(d);}
  if(isInc) window._incReceiptData=null;
  // تسجيل تلقائي في القروض
  if(isInc && paymentType==='loan_received'){
    const lPerson=(document.getElementById('in-loan-person')?.value||'').trim();
    if(lPerson){
      if(!S.loans) S.loans=[];
      S.loans.push({id:'ln_'+Date.now(),direction:'borrowed',amount,
        person:lPerson,phone:document.getElementById('in-loan-phone')?.value||'',
        date:isoDate,due:document.getElementById('in-loan-due')?.value||'',
        notes:'',status:'pending',settledAmount:0,
        createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()});
      toast('🤝 تم تسجيل القرض في صفحة القروض');
    }
  }
  if(!isInc && expCat==='سلفة للغير'){
    const lPerson=(document.getElementById('ex-loan-person')?.value||'').trim();
    if(lPerson){
      if(!S.loans) S.loans=[];
      S.loans.push({id:'ln_'+Date.now(),direction:'lent',amount,
        person:lPerson,phone:document.getElementById('ex-loan-phone')?.value||'',
        date:isoDate,due:document.getElementById('ex-loan-due')?.value||'',
        notes:'',status:'pending',settledAmount:0,
        createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()});
      toast('🤝 تم تسجيل السلفة في صفحة القروض');
    }
  }
  lsSave();closeM(isInc?'modal-income':'modal-expense');renderAll();
  // Auto-print receipt for income transactions
  if(isInc){
    const savedId = eid ? +eid : S.transactions[S.transactions.length-1]?.id;
    if(savedId) setTimeout(()=>exportReceipt(savedId), 400);
  }
}
function delTrans(id){
  confirmDel('هل تريد حذف هذه المعاملة؟',()=>{
    // لو المعاملة مرتبطة بـ project_task، ضع flag عشان الـ sync مش يرجعها
    var tx=S.transactions.find(t=>String(t.id)===String(id));
    if(tx && tx.linkedProjTaskId){
      var pt=(S.project_tasks||[]).find(t=>String(t.id)===String(tx.linkedProjTaskId));
      if(pt) pt._txDeleted=true;
    }
    S.transactions=S.transactions.filter(t=>String(t.id)!==String(id));
    lsSave();cloudSave(S);renderAll();
  });
}
// Finance filter state
let finFilterState = {month:'', year:'', type:'', method:'', cat:'', project:''};

function populateFinYears(){
  const sel = document.getElementById('fin-filter-year'); if(!sel) return;
  const cur = sel.value;
  sel.innerHTML = '<option value="">كل السنوات</option>';
  const years = [...new Set(S.transactions.map(t=>t.isoDate?t.isoDate.slice(0,4):null).filter(Boolean))].sort();
  const thisYear = new Date().getFullYear().toString();
  if(!years.includes(thisYear)) years.push(thisYear);
  years.sort().forEach(y=>{const o=document.createElement('option');o.value=y;o.textContent=y;sel.appendChild(o);});
  sel.value = cur;
}

function _toggleFinFilterPanel(){
  var panel=document.getElementById('_fin-filter-panel');
  var btn=document.getElementById('_fin-filter-toggle');
  if(!panel) return;
  var isOpen=panel.style.display!=='none';
  panel.style.display=isOpen?'none':'';
  if(btn){
    btn.style.borderColor=isOpen?'var(--border)':'var(--accent)';
    btn.style.color=isOpen?'var(--text2)':'var(--accent)';
    btn.style.background=isOpen?'var(--surface2)':'rgba(124,111,247,.08)';
  }
}
function _updateFinFilterDot(){
  var dot=document.getElementById('_fin-filter-dot');
  if(!dot) return;
  var f=finFilterState;
  var hasFilter=f.month||f.year||f.type||f.method||f.cat||f.project;
  dot.style.display=hasFilter?'block':'none';
}

function applyFinanceFilter(){
  finFilterState.month   = document.getElementById('fin-filter-month')?.value||'';
  finFilterState.year    = document.getElementById('fin-filter-year')?.value||'';
  finFilterState.type    = document.getElementById('fin-filter-type')?.value||'';
  finFilterState.method  = document.getElementById('fin-filter-method')?.value||'';
  finFilterState.cat     = document.getElementById('fin-filter-cat')?.value||'';
  finFilterState.project = document.getElementById('fin-filter-project')?.value||'';
  _updateFinFilterDot();
  renderFinance();
}

function resetFinanceFilter(){
  finFilterState = {month:'',year:'',type:'',method:'',cat:'',project:''};
  ['fin-filter-month','fin-filter-year','fin-filter-type','fin-filter-method','fin-filter-cat','fin-filter-project'].forEach(id=>{
    const el=document.getElementById(id);if(el)el.value='';
  });
  _updateFinFilterDot();
  renderFinance();
}

function filterTransactions(transactions){
  const f = finFilterState;
  return transactions.filter(t=>{
    const d = t.isoDate || '';
    if(f.month   && d.slice(5,7) !== f.month.padStart(2,'0')) return false;
    if(f.year    && d.slice(0,4) !== f.year) return false;
    if(f.type    && t.type !== f.type) return false;
    if(f.method  && (t.payMethod||'cash') !== f.method) return false;
    if(f.cat     && (t.expCat||t.source||'') !== f.cat) return false;
    if(f.project && String(t.project_id||'') !== String(f.project)) return false;
    return true;
  });
}


// ── Sync project task income to S.transactions (auto-record) ──
// ملحوظة: لو المستخدم حذف المعاملة يدوياً، مش بنرجعها تاني
function _syncProjTaskTransactions(){
  if(!S.project_tasks) return;
  if(!S.transactions) S.transactions=[];
  S.project_tasks.forEach(function(t){
    if(!t.paymentCollected || !t.value || t.value<=0) return;
    // لو المستخدم حذف المعاملة يدوياً (manuallyDeleted flag) متتسجلش تاني
    if(t._txDeleted) return;
    // Check if already recorded
    var exists=S.transactions.some(function(tx){return String(tx.linkedProjTaskId)===String(t.id);});
    if(!exists){
      var proj=_getProjById?_getProjById(t.project_id):null;
      S.transactions.push({
        id:Date.now()+Math.random(),
        type:'income',
        amount:t.value,
        currency:t.currency||'ج.م',
        desc:'مهمة مشروع: '+(t.title||'')+(proj?' — '+proj.name:''),
        date:t.createdAt?t.createdAt.slice(0,10):new Date().toISOString().slice(0,10),
        isoDate:t.createdAt?t.createdAt.slice(0,10):new Date().toISOString().slice(0,10),
        linkedProjTaskId:t.id,
        source:'project_task',
        createdAt:new Date().toISOString()
      });
    }
  });
}
function renderFinance(){
  // Sync project task completions into transactions (avoid duplicates)
  _syncProjTaskTransactions();
  populateFinYears();
  // Populate project filter
  (function(){
    var sel = document.getElementById('fin-filter-project');
    if(!sel) return;
    var cur = sel.value;
    sel.innerHTML = '<option value="">كل المشاريع</option>';
    (S.projects||[]).forEach(function(p){
      var opt = document.createElement('option');
      opt.value = p.id;
      opt.textContent = p.name;
      sel.appendChild(opt);
    });
    if(cur) sel.value = cur;
  })();
  renderMonthlyTimeline();
  renderFinLoansSummary();
  const filtered = filterTransactions(S.transactions);
  const f = finFilterState;
  
  // Label for current filter
  const lbl = document.getElementById('fin-filter-label');
  if(lbl){
    const months = ['','يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
    let parts = [];
    if(f.month) parts.push(months[+f.month]||'');
    if(f.year)  parts.push(f.year);
    lbl.innerHTML = parts.length ? '<i class="fa-solid fa-calendar-days"></i> '+parts.join(' ') : '';
  }

  const inc = filtered.filter(t=>t.type==='income'&&!t.isLoan).reduce((s,t)=>s+t.amount,0);
  const exp = filtered.filter(t=>t.type==='expense'&&t.expCat!=='سلفة للغير').reduce((s,t)=>s+t.amount,0);
  const net = inc-exp, margin = inc?Math.round(net/inc*100):0;
  
  // Category breakdown
  const catSum = cat => filtered.filter(t=>t.type==='expense'&&t.source===cat).reduce((s,t)=>s+t.amount,0);
  const personalSum = filtered.filter(t=>t.type==='expense'&&(t.source==='سحب شخصي'||t.source==='مصاريف تعليمية شخصية')).reduce((s,t)=>s+t.amount,0);
  
  // Pending tasks (global, not filtered)
  const pendingTasks=S.tasks.filter(t=>!t.done&&t.status!=='done'&&t.pay!=='full');
  const pendingRev=pendingTasks.reduce((s,t)=>s+(t.value||0),0);
  const depositsPending=pendingTasks.filter(t=>t.pay==='deposit').reduce((s,t)=>s+(t.deposit||0),0);
  
  const set=(id,val)=>{const e=document.getElementById(id);if(e)e.textContent=val;};
  set('fin-in',inc.toLocaleString()+' '+_getCurrency());
  set('fin-in-sub', f.month||f.year ? `(${(f.month?'الشهر':'')+(f.year?' '+f.year:'')})` : '');
  set('fin-out',exp.toLocaleString()+' '+_getCurrency());
  set('fin-net',net.toLocaleString()+' '+_getCurrency());
  set('fin-margin',inc?margin+'%':'—');
  set('fin-pending',pendingRev.toLocaleString()+' '+_getCurrency());
  set('fin-deposits',depositsPending.toLocaleString()+' '+_getCurrency());
  
  // Category cards
  
  // Unpaid task reminders
  renderUnpaidReminders();
  
  const tbody=document.getElementById('fin-tbody');if(!tbody)return;
  const rows = [...filtered].sort((a,b)=>(b.isoDate||'').localeCompare(a.isoDate||'')).map(t=>{
    const projBadge = t.project_id ? (()=>{const pj=(S.projects||[]).find(p=>String(p.id)===String(t.project_id));return pj?` <span style="font-size:10px;background:rgba(79,209,165,.12);color:#4fd1a5;padding:1px 7px;border-radius:8px;cursor:pointer" onclick="showPage('projects');setTimeout(()=>openProjectDetail('${pj.id}'),200)"><i class="fa-solid fa-diagram-project"></i> ${pj.name.slice(0,18)}</span>`:''})() : '';
    return `<tr>
    <td>${t.desc||'—'}${projBadge}${t.linkedTaskId?(()=>{const lt=S.tasks.find(x=>x.id===t.linkedTaskId);return lt?` <span style="font-size:10px;background:rgba(124,111,247,.15);color:var(--accent);padding:1px 6px;border-radius:8px;cursor:pointer" onclick="openTaskDetail(${t.linkedTaskId})"><i class="fa-solid fa-link"></i> ${lt.title.slice(0,20)}</span>`:''})():''}</td><td class="hide-mobile">${t.source||'—'}${t.paymentType&&t.paymentType!=='full'?` <span style="font-size:10px;color:var(--accent2)">(${t.paymentType==='deposit'?'عربون':'جزئي'})</span>`:''}</td>
    <td><span class="badge ${t.type==='income'?'badge-green':'badge-red'}">${t.type==='income'?'<i class="fa-solid fa-coins"></i> دخل':'<i class="fa-solid fa-money-bill-wave"></i> مصروف'}</span></td>
    <td style="font-weight:700;color:${t.type==='income'?'var(--accent3)':'var(--accent4)'}">${t.amount.toLocaleString()} ج</td>
    <td class="hide-mobile" style="font-family:var(--mono);font-size:11px">${t.isoDate||t.date||'—'}</td>
    <td><div style="display:flex;gap:4px">
      <button class="btn btn-ghost btn-sm" onclick="${t.type==='income'?'openIncomeModal':'openExpenseModal'}(${t.id})"><i class="fa-solid fa-pen"></i></button>
      ${t.type==='income'?`<button class="btn btn-ghost btn-sm" onclick="exportReceipt(${t.id})" title="إيصال PDF" style="color:var(--accent3)"><i class="fa-solid fa-receipt"></i></button>`:''}
      <button class="btn btn-danger btn-sm" onclick="delTrans(${t.id})"><i class="fa-solid fa-trash"></i></button>
    </div></td>
  </tr>`;}).join('');
  tbody.innerHTML = rows || '<tr><td colspan="6" style="text-align:center;color:var(--text3);padding:24px">لا معاملات تطابق الفلتر</td></tr>';
}

function renderUnpaidReminders(){
  const wrap = document.getElementById('fin-unpaid-reminders'); if(!wrap) return;
  // Find completed tasks whose payment was not collected
  const _projUncollected=(S.project_tasks||[]).filter(t=>t.status==='done'&&!t.paymentCollected&&t.value>0).map(t=>{
    var proj=_getProjById&&_getProjById(t.project_id);
    return Object.assign({},t,{title:(proj?proj.name+' — ':'')+t.title,_isProjTask:true});
  });
  const uncollected = [...S.tasks.filter(t=>t.done && !t.paymentCollected && t.value>0), ..._projUncollected];

  // تذكيرات القروض المتأخرة
  const today = new Date(); today.setHours(0,0,0,0);
  const loans = S.loans || [];
  const overdueLoans = loans.filter(function(l){ return l.due && l.status!=='settled' && new Date(l.due)<today; });
  const dueSoonLoans = loans.filter(function(l){
    if(!l.due || l.status==='settled') return false;
    const d = new Date(l.due); d.setHours(0,0,0,0);
    const diff = Math.round((d-today)/(1000*60*60*24));
    return diff>=0 && diff<=7;
  });

  // مستحقات العملاء (رصيد افتتاحي)
  const clientsOwing = (S.clients||[]).filter(function(c){ return c.openingBalance>0 && c.openingBalanceType==='receivable'; });

  const hasItems = uncollected.length || overdueLoans.length || dueSoonLoans.length || clientsOwing.length;
  if(!hasItems){ wrap.style.display='none'; return; }
  wrap.style.display='block';
  const cur = _getCurrency();

  let html = '';

  if(uncollected.length){
    html += `<div class="card" style="border-color:rgba(247,201,72,.4);margin-bottom:10px">
      <div style="font-size:13px;font-weight:700;color:var(--accent2);margin-bottom:10px"><i class="fa-solid fa-triangle-exclamation"></i> مبالغ لم يتم تحصيلها</div>
      ${uncollected.map(t=>`
        <div style="display:flex;align-items:center;gap:12px;padding:9px 0;border-bottom:1px solid rgba(42,42,58,.4)">
          <div style="flex:1">
            <div style="font-size:13px;font-weight:600">${t.title}</div>
            <div style="font-size:11px;color:var(--text3)">${t.client||'—'}</div>
          </div>
          <div style="font-weight:700;color:var(--accent2)">${t.value.toLocaleString()} ${cur}</div>
          <button class="btn btn-success btn-sm" onclick="markTaskPaymentCollected(${t.id})"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم التحصيل</button>
        </div>`).join('')}
    </div>`;
  }

  if(overdueLoans.length){
    html += `<div class="card" style="border-color:rgba(255,107,107,.5);margin-bottom:10px">
      <div style="font-size:13px;font-weight:700;color:var(--accent4);margin-bottom:10px"><i class="fa-solid fa-bell"></i> قروض متأخرة السداد (${overdueLoans.length})</div>
      ${overdueLoans.map(l=>`
        <div style="display:flex;align-items:center;gap:12px;padding:9px 0;border-bottom:1px solid rgba(42,42,58,.4)">
          <div style="flex:1">
            <div style="font-size:13px;font-weight:600">${l.direction==='lent'?'💰 سلّفت لـ ':'↩ استلفت من '}${escapeHtml(l.person)}</div>
            <div style="font-size:11px;color:var(--accent4)">⚠️ استحق: ${l.due}</div>
          </div>
          <div style="font-weight:700;color:var(--accent4)">${(l.amount-(l.settledAmount||0)).toLocaleString()} ${cur}</div>
          <button class="btn btn-ghost btn-sm" onclick="switchFinTab('loans');showPage('finance')"><i class="fa-solid fa-handshake"></i> عرض</button>
        </div>`).join('')}
    </div>`;
  }

  if(dueSoonLoans.length){
    html += `<div class="card" style="border-color:rgba(247,201,72,.4);margin-bottom:10px">
      <div style="font-size:13px;font-weight:700;color:var(--accent2);margin-bottom:10px"><i class="fa-solid fa-calendar-days"></i> قروض موعدها خلال 7 أيام</div>
      ${dueSoonLoans.map(l=>{
        const daysLeft = Math.round((new Date(l.due)-today)/(1000*60*60*24));
        return `<div style="display:flex;align-items:center;gap:12px;padding:9px 0;border-bottom:1px solid rgba(42,42,58,.4)">
          <div style="flex:1">
            <div style="font-size:13px;font-weight:600">${l.direction==='lent'?'💰 سلّفت لـ ':'↩ استلفت من '}${escapeHtml(l.person)}</div>
            <div style="font-size:11px;color:var(--accent2)">📅 الموعد: ${l.due} (${daysLeft===0?'اليوم!':daysLeft+' أيام'})</div>
          </div>
          <div style="font-weight:700;color:var(--accent2)">${(l.amount-(l.settledAmount||0)).toLocaleString()} ${cur}</div>
        </div>`;
      }).join('')}
    </div>`;
  }

  if(clientsOwing.length){
    const totalOwing = clientsOwing.reduce(function(s,c){ return s+(+c.openingBalance||0); },0);
    html += `<div class="card" style="border-color:rgba(168,156,255,.4);margin-bottom:10px">
      <div style="font-size:13px;font-weight:700;color:var(--accent2);margin-bottom:10px"><i class="fa-solid fa-users"></i> عملاء عندهم رصيد مستحق — إجمالي: ${totalOwing.toLocaleString()} ${cur}</div>
      ${clientsOwing.map(c=>`
        <div style="display:flex;align-items:center;gap:12px;padding:7px 0;border-bottom:1px solid rgba(42,42,58,.4)">
          <div style="flex:1;font-size:12px;font-weight:700">${escapeHtml(c.name)}</div>
          <div style="font-size:12px;font-weight:700;color:var(--accent2)">${(+c.openingBalance).toLocaleString()} ${cur}</div>
          <button class="btn btn-ghost btn-sm" onclick="openClientProfile(${c.id})"><i class="fa-solid fa-user"></i> عرض</button>
        </div>`).join('')}
    </div>`;
  }

  wrap.innerHTML = html;
}

function markTaskPaymentCollected(taskId){
  // Check project task first
  var ptask=(S.project_tasks||[]).find(function(t){return String(t.id)===String(taskId);});
  if(ptask){
    ptask.paymentCollected=true;
    if(ptask.value>0){
      if(!S.transactions) S.transactions=[];
      var proj=typeof _getProjById==='function'?_getProjById(ptask.project_id):null;
      S.transactions.push({id:Date.now()+Math.random(),type:'income',amount:ptask.value,
        currency:ptask.currency||'ج.م',
        desc:'تحصيل: '+(ptask.title||'')+(proj?' — '+proj.name:''),
        date:new Date().toISOString().slice(0,10),
        linkedProjTaskId:ptask.id,source:'project_task',createdAt:new Date().toISOString()});
    }
    lsSave(); cloudSave(S);
    if(typeof renderFinance==='function') renderFinance();
    if(typeof renderProjectDetail==='function') renderProjectDetail();
    toast('<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم تسجيل التحصيل');
    return;
  }
  const task = S.tasks.find(x=>x.id===taskId); if(!task) return;
  task.paymentCollected = true;
  lsSave();
  // Open income modal pre-filled with task info so user can review before saving
  openIncomeModal(null, taskId);
  const amtEl=document.getElementById('in-amount');
  if(amtEl) amtEl.value = task.value||0;
  const srcEl=document.getElementById('in-source');
  if(srcEl) srcEl.value = task.client||'';
  const descEl=document.getElementById('in-desc');
  if(descEl) descEl.value = 'تحصيل مبلغ مشروع: '+task.title;
  const ptEl=document.getElementById('in-payment-type');
  if(ptEl) ptEl.value = 'full';
  renderAll();
}

// ============================================================
// INVOICES
// ============================================================
/* ── عرض مهام العميل في مودال الفاتورة ── */
function onInvClientChange(clientName){
  const name = clientName || document.getElementById('inv-client')?.value || '';
  const panel = document.getElementById('inv-tasks-panel');
  const list  = document.getElementById('inv-tasks-list');
  if(!panel||!list) return;
  if(!name){ panel.style.display='none'; return; }

  // كل تاسكات العميل — مش بس الجاري، كمان المكتملة والمدفوعة
  const tasks = S.tasks.filter(t => t.client === name);
  if(!tasks.length){ panel.style.display='none'; return; }

  // معرفة أي مهام عندها فواتير بالفعل
  const invoicedTaskIds = new Set(
    S.invoices.flatMap(inv => inv.items.map(it => it._taskId).filter(Boolean))
  );

  const statusLabel = {new:'جديد', progress:'جاري', review:'مراجعة', done:'مكتمل'};
  const statusColor = {new:'var(--text3)', progress:'var(--accent2)', review:'var(--accent)', done:'var(--accent3)'};

  list.innerHTML = tasks.map(t => {
    const already      = invItems.some(it => it._taskId === t.id);
    const hasInvoice   = invoicedTaskIds.has(t.id);
    const isPaidFull   = t.pay === 'full' || t.done;
    const isPaidDeposit= t.pay === 'deposit';
    const isUnpaid     = !isPaidFull && !isPaidDeposit;

    // بطاقة الدفع
    let payBadge = '';
    if(isPaidFull)
      payBadge = `<span style="background:rgba(79,209,165,.15);color:var(--accent3);padding:1px 7px;border-radius:20px;font-size:10px;font-weight:700"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> مدفوع</span>`;
    else if(isPaidDeposit)
      payBadge = `<span style="background:rgba(247,201,72,.15);color:var(--accent2);padding:1px 7px;border-radius:20px;font-size:10px;font-weight:700"><i class="fa-solid fa-heart"></i> عربون ${t.deposit?t.deposit.toLocaleString()+' ج':''}</span>`;
    else
      payBadge = `<span style="background:rgba(255,99,99,.12);color:#ff6b6b;padding:1px 7px;border-radius:20px;font-size:10px;font-weight:700"><i class="fa-solid fa-circle-xmark"></i> غير مدفوع</span>`;

    // بطاقة الفاتورة
    const invBadge = hasInvoice
      ? `<span style="background:rgba(124,111,247,.15);color:var(--accent);padding:1px 7px;border-radius:20px;font-size:10px;font-weight:700"><i class="fa-solid fa-square"></i> عليها فاتورة</span>`
      : '';

    // لون الكارد
    const cardBg     = already ? 'rgba(124,111,247,.16)' : isPaidFull ? 'rgba(79,209,165,.05)' : 'var(--surface2)';
    const cardBorder = already ? 'var(--accent)' : isPaidFull ? 'rgba(79,209,165,.3)' : 'var(--border)';
    const icon       = already ? '<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i>' : hasInvoice ? '<i class="fa-solid fa-repeat"></i>' : '➕';

    return `<div id="task-chip-${t.id}" onclick="toggleTaskAsItem(${t.id})"
      style="display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:8px;cursor:pointer;
             background:${cardBg};border:1.5px solid ${cardBorder};transition:all .18s">
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${t.title}</div>
        <div style="font-size:11px;margin-top:4px;display:flex;gap:6px;flex-wrap:wrap;align-items:center">
          <span style="color:${statusColor[t.status]||'var(--text3)'}">● ${statusLabel[t.status]||t.status}</span>
          ${t.deadline ? `<span style="color:var(--text3)"><i class="fa-solid fa-calendar-days"></i> ${t.deadline}</span>` : ''}
          ${t.value    ? `<span style="color:var(--accent3);font-weight:700">${t.value.toLocaleString()} ج</span>` : ''}
          ${payBadge}
          ${invBadge}
        </div>
        ${isPaidFull && t.value ? `<div style="font-size:10px;color:var(--accent3);margin-top:4px">↪ سيُضاف ${t.value.toLocaleString()} ج كمدفوع مسبقاً في الفاتورة</div>` : ''}
        ${isPaidDeposit && t.deposit ? `<div style="font-size:10px;color:var(--accent2);margin-top:4px">↪ سيُضاف العربون ${t.deposit.toLocaleString()} ج كمدفوع مسبقاً في الفاتورة</div>` : ''}
      </div>
      <div style="font-size:18px;flex-shrink:0">${icon}</div>
    </div>`;
  }).join('');

  panel.style.display = 'block';
}

/* إضافة / إزالة مهمة كبند — مع منطق الدفع المسبق */
function toggleTaskAsItem(taskId){
  const t = S.tasks.find(x => x.id === taskId);
  if(!t) return;

  const idx = invItems.findIndex(it => it._taskId === taskId);

  if(idx > -1){
    // إزالة البند
    invItems.splice(idx, 1);
    // إعادة حساب العربون — اطرح ما أضفناه
    _recalcDepositFromItems();
  } else {
    // إضافة البند
    const isPaidFull    = t.pay === 'full' || t.done;
    const isPaidDeposit = t.pay === 'deposit';

    invItems.push({
      _taskId: taskId,
      desc:  t.title + (t.notes ? ' — ' + t.notes.slice(0, 60) : ''),
      qty:   1,
      price: t.value || 0
    });

    // تحديث خانة "مدفوع مسبقاً"
    const depEl = document.getElementById('inv-deposit');
    if(depEl){
      const currentDep = +(depEl.value) || 0;
      if(isPaidFull && t.value){
        depEl.value = currentDep + t.value;
      } else if(isPaidDeposit && t.deposit){
        depEl.value = currentDep + t.deposit;
      }
    }
  }

  renderInvForm();
  calcTotal();
  const client = document.getElementById('inv-client')?.value || '';
  onInvClientChange(client);
}

/* إعادة حساب خانة العربون بناءً على البنود المتبقية */
function _recalcDepositFromItems(){
  let dep = 0;
  invItems.forEach(it => {
    if(!it._taskId) return;
    const t = S.tasks.find(x => x.id === it._taskId);
    if(!t) return;
    if((t.pay==='full'||t.done) && t.value)   dep += t.value;
    else if(t.pay==='deposit' && t.deposit)    dep += t.deposit;
  });
  const depEl = document.getElementById('inv-deposit');
  if(depEl) depEl.value = dep || 0;
  calcTotal();
}

function openInvoiceModal(id){
  fillDD('inv-client');
  document.getElementById('inv-modal-ttl').innerHTML=id?'<i class="fa-solid fa-square"></i> تعديل الفاتورة':'<i class="fa-solid fa-square"></i> إنشاء فاتورة جديدة';
  document.getElementById('inv-eid').value=id||'';
  // إخفاء لوحة المهام أول ما نفتح
  const panel=document.getElementById('inv-tasks-panel');
  if(panel)panel.style.display='none';
  if(id){
    const inv=S.invoices.find(i=>i.id===id);if(!inv)return;
    document.getElementById('inv-client').value=inv.client;
    document.getElementById('inv-num').value=inv.num;
    document.getElementById('inv-date').value=inv.date;
    document.getElementById('inv-due').value=inv.due;
    document.getElementById('inv-notes').value=inv.notes||'';
    document.getElementById('inv-deposit').value=inv.deposit||0;
    invItems=inv.items.map(i=>({...i}));
    invPolicies=(inv.policies||[]).map(p=>({...p}));
    const puEl=document.getElementById('inv-project-url');
    if(puEl)puEl.value=inv.projectUrl||'';
    const plEl=document.getElementById('inv-payment-link');
    if(plEl)plEl.value=inv.paymentLink||'';
    // عرض مهام العميل
    setTimeout(()=>onInvClientChange(inv.client),120);
  } else {
    document.getElementById('inv-client').value='';
    document.getElementById('inv-num').value='INV-'+(S.invoices.length+1).toString().padStart(3,'0');
    document.getElementById('inv-date').value=today();
    const d=new Date();d.setDate(d.getDate()+7);
    document.getElementById('inv-due').value=d.toISOString().split('T')[0];
    document.getElementById('inv-notes').value=S.settings?.terms||'';
    invItems=[{desc:'',qty:1,price:0}];
    invPolicies=(S.settings?.policies||[]).map(p=>({...p}));
    const plElN=document.getElementById('inv-payment-link'); if(plElN) plElN.value='';
  }
  setTimeout(()=>{
    const dep=document.getElementById('inv-deposit');if(dep){dep.oninput=calcTotal;}
    renderPoliciesList('inv-policies-list',invPolicies,'removeInvPolicy');
    const projEl=document.getElementById('inv-project-url');
    if(projEl)liveQR('inv-project-url','inv-project-qr-prev',90);
  },100);
  renderInvForm();openM('modal-invoice');
}
function addInvItem(){invItems.push({desc:'',qty:1,price:0});renderInvForm();}
function renderInvForm(){
  const el=document.getElementById('inv-items-container');if(!el)return;
  el.innerHTML=invItems.map((item,i)=>`
    <div style="display:grid;grid-template-columns:1fr 70px 100px 34px;gap:7px;margin-bottom:8px;align-items:center">
      <input class="form-input" placeholder="وصف البند" value="${item.desc.replace(/"/g,'&quot;')}" oninput="invItems[${i}].desc=this.value">
      <input class="form-input" type="number" placeholder="كمية" value="${item.qty}" oninput="invItems[${i}].qty=+this.value;calcTotal()">
      <input class="form-input" type="number" placeholder="سعر ج" value="${item.price||''}" oninput="invItems[${i}].price=+this.value;calcTotal()">
      <button class="btn btn-danger" style="padding:8px;justify-content:center" onclick="invItems.splice(${i},1);renderInvForm()"><i class="fa-solid fa-xmark"></i></button>
    </div>`).join('');
  calcTotal();
}
function calcTotal(){
  const t=invItems.reduce((s,i)=>s+(+i.qty||0)*(+i.price||0),0);
  const e=document.getElementById('inv-total-live');if(e)e.textContent=t.toLocaleString();
  const dep=+(document.getElementById('inv-deposit')?.value||0);
  const rem=document.getElementById('inv-remaining-preview');
  if(rem)rem.textContent=dep>0?(t-dep).toLocaleString()+' ج متبقي':'—';
}
function saveInvoice(){
  const client=v('inv-client');if(!client)return alert('اختر العميل');
  if(!invItems.some(i=>i.desc.trim()))return alert('أضف بنداً واحداً على الأقل');
  const total=invItems.reduce((s,i)=>s+i.qty*i.price,0);
  const eid=v('inv-eid');

  // Find parent client - if this client is a sub, link to parent
  const clientObj = S.clients.find(c=>c.name===client);
  let parentClientName = null;
  if(clientObj && clientObj.workType==='sub' && clientObj.parentClientId){
    const parentObj = S.clients.find(c=>String(c.id)===String(clientObj.parentClientId));
    if(parentObj) parentClientName = parentObj.name;
  }

  const d={
    client,
    parentClient: parentClientName, // الشركة الأم إن وُجدت
    num:v('inv-num'),date:v('inv-date'),due:v('inv-due'),notes:v('inv-notes'),
    items:invItems.map(i=>({...i})),total,deposit:+(v('inv-deposit')||0),
    from:S.settings?.name||'العمل',status:'pending',
    policies:invPolicies.map(p=>({...p})),
    projectUrl:(document.getElementById('inv-project-url')?.value||'').trim(),
    paymentLink:(document.getElementById('inv-payment-link')?.value||'').trim(),
    receiptImage: window._invReceiptData||null
  };
  if(eid){const i=S.invoices.findIndex(x=>x.id==eid);if(i>-1){d.id=+eid;d.status=S.invoices[i].status;if(!d.receiptImage&&S.invoices[i].receiptImage)d.receiptImage=S.invoices[i].receiptImage;S.invoices[i]=d;}}
  else{ if(!checkLimit('max_invoices', S.invoices.length)) return; d.id=Date.now();S.invoices.push(d);}
  window._invReceiptData=null;
  lsSave();closeM('modal-invoice');renderInvoices();updateDash();previewInv(d.id);
}
function delInvoice(id){
  confirmDel('هل تريد حذف هذه الفاتورة؟',()=>{
    S.invoices=S.invoices.filter(i=>i.id!==id);lsSave();renderAll();
    document.getElementById('inv-preview-card').innerHTML='<div class="section-title">معاينة الفاتورة</div><div class="empty"><div class="empty-icon"><i class="fa-solid fa-square"></i></div>اختر فاتورة أو أنشئ جديدة</div>';
  });
}
function markPaid(id){const inv=S.invoices.find(i=>i.id===id);if(inv){inv.status='paid';inv.collectedAt=new Date().toISOString().split('T')[0];lsSave();renderAll();previewInv(id);showMiniNotif('<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم تسجيل التحصيل');}}
function markUncollected(id){const inv=S.invoices.find(i=>i.id===id);if(inv){inv.status='pending';inv.collectedAt=null;lsSave();renderAll();previewInv(id);}}

// ============================================================
// RECEIPT PDF — إيصال استلام مبلغ
// ============================================================
function exportReceipt(transId){
  const t = S.transactions.find(x=>x.id===transId);
  if(!t) return;
  const s = S.settings||{};
  const logo = s.logo ? `<img src="${s.logo}" style="max-height:56px;max-width:130px;object-fit:contain" onerror="this.style.display=\'none\'">` : `<div style="font-size:20px;font-weight:900;color:#7c6ff7">${s.name||'Ordo'}</div>`;
  const linkedTask = t.linkedTaskId ? S.tasks.find(x=>x.id===t.linkedTaskId) : null;
  const payTypeAr = {full:'دفعة كاملة',deposit:'عربون',partial:'دفعة جزئية'}[t.paymentType||'full'] || 'دفعة';
  const receiptNum = 'RCP-' + String(transId).slice(-5);
  const dateStr = t.isoDate ? new Date(t.isoDate+'T00:00:00').toLocaleDateString('ar-EG',{year:'numeric',month:'long',day:'numeric'}) : t.date||'';
  const receiptHTML = `<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap" rel="stylesheet">
<style>*{margin:0;padding:0;box-sizing:border-box;}body{font-family:'Cairo',sans-serif;background:#fff;color:#1a1a2e;direction:rtl;}@page{size:A4;margin:0;}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact;}}</style>
</head><body><div style="width:210mm;min-height:297mm;background:#fff">
<div style="background:#14141e;padding:22px 28px;display:flex;justify-content:space-between;align-items:center">
  <div>${logo}</div>
  <div style="text-align:left"><div style="font-size:24px;font-weight:900;color:#4fd1a5">إيصال استلام</div><div style="font-size:11px;color:#b0a8ff;margin-top:3px">${receiptNum}</div></div>
</div>
<div style="height:3px;background:linear-gradient(to left,#4fd1a5,#7c6ff7)"></div>
<div style="display:flex;justify-content:space-between;padding:22px 28px;background:#f7fffe">
  <div><div style="font-size:10px;color:#888;margin-bottom:4px">صادر من</div><div style="font-size:14px;font-weight:700">${s.name||'العمل'}</div>${s.phone?`<div style="font-size:11px;color:#555;margin-top:2px"><i class="fa-solid fa-phone"></i> ${s.phone}</div>`:''}</div>
  <div style="text-align:left"><div style="font-size:10px;color:#888;margin-bottom:4px">بيانات الإيصال</div><div style="font-size:13px;font-weight:700">رقم: ${receiptNum}</div><div style="font-size:11px;color:#555;margin-top:3px">التاريخ: ${dateStr}</div></div>
</div>
<div style="margin:0 28px 24px;background:linear-gradient(135deg,#14141e,#1e1e30);border-radius:12px;padding:24px 28px;display:flex;justify-content:space-between;align-items:center">
  <div><div style="font-size:11px;color:#b0a8ff;margin-bottom:6px">تم استلام مبلغ</div>
    <div style="font-size:36px;font-weight:900;color:#4fd1a5">${t.amount.toLocaleString()} <span style="font-size:18px">ج.م</span></div>
    <div style="margin-top:8px;display:inline-block;background:rgba(79,209,165,.2);color:#4fd1a5;padding:3px 12px;border-radius:20px;font-size:11px;font-weight:700">${payTypeAr}</div>
  </div>
  <div style="text-align:left"><div style="font-size:11px;color:#b0a8ff;margin-bottom:3px">من</div><div style="font-size:15px;font-weight:700;color:#fff">${t.source||'—'}</div></div>
</div>
<div style="margin:0 28px 24px;border:1px solid #e8e8f0;border-radius:10px;overflow:hidden">
  <div style="padding:10px 16px;background:#f8f8fc;font-size:10px;font-weight:700;color:#666;text-transform:uppercase;letter-spacing:.5px">تفاصيل الإيصال</div>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:11px 16px;font-size:12px;color:#888;border-bottom:1px solid #f0f0f5;width:38%">الوصف</td><td style="padding:11px 16px;font-size:13px;font-weight:600;border-bottom:1px solid #f0f0f5">${t.desc||'—'}</td></tr>
    ${linkedTask ? `<tr><td style="padding:11px 16px;font-size:12px;color:#888;border-bottom:1px solid #f0f0f5">المشروع</td><td style="padding:11px 16px;font-size:13px;font-weight:600;border-bottom:1px solid #f0f0f5"><i class="fa-solid fa-clipboard-list"></i> ${linkedTask.title}</td></tr><tr><td style="padding:11px 16px;font-size:12px;color:#888;border-bottom:1px solid #f0f0f5">العميل</td><td style="padding:11px 16px;font-size:13px;font-weight:600;border-bottom:1px solid #f0f0f5">${linkedTask.client||'—'}</td></tr>` : ''}
    <tr><td style="padding:11px 16px;font-size:12px;color:#888;border-bottom:1px solid #f0f0f5">نوع الدفعة</td><td style="padding:11px 16px;font-size:13px;font-weight:600;border-bottom:1px solid #f0f0f5">${payTypeAr}</td></tr>
    <tr><td style="padding:11px 16px;font-size:12px;color:#888">تاريخ الاستلام</td><td style="padding:11px 16px;font-size:13px;font-weight:600">${dateStr}</td></tr>
  </table>
</div>
<div style="margin:0 28px;padding:16px;border-top:2px solid #f0f0f5;display:flex;justify-content:space-between;align-items:center">
  <div style="font-size:11px;color:#aaa">هذا الإيصال يُثبت استلام المبلغ المذكور أعلاه</div>
  <div style="font-size:11px;color:#aaa">توقيع: _______________</div>
</div>
${s.terms?`<div style="margin:12px 28px;padding:12px;background:#fafafe;border-radius:8px;font-size:10px;color:#888;line-height:1.6">${s.terms}</div>`:''}
</div></body></html>`;
  // Use hidden iframe to avoid popup blockers
  let iframe = document.getElementById('_receipt_frame');
  if(!iframe){
    iframe = document.createElement('iframe');
    iframe.id = '_receipt_frame';
    iframe.style.cssText = 'position:fixed;top:-9999px;left:-9999px;width:1px;height:1px;border:none;';
    document.body.appendChild(iframe);
  }
  iframe.srcdoc = receiptHTML;
  iframe.onload = () => {
    try { iframe.contentWindow.focus(); iframe.contentWindow.print(); }
    catch(e){ 
      // fallback: open in new tab
      const w = window.open('','_blank'); w.document.write(receiptHTML); w.document.close(); setTimeout(()=>w.print(),600);
    }
  };
}

function renderInvoices(){
  const tbody=document.getElementById('inv-tbody');if(!tbody)return;
  const sm={
    pending:'<span class="inv-status-badge inv-uncollected">⏳ لم يتم التحصيل</span>',
    paid:'<span class="inv-status-badge inv-collected"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم التحصيل</span>',
    cancelled:'<span class="inv-status-badge inv-cancelled">🚫 ملغية</span>'
  };
  tbody.innerHTML=S.invoices.map(inv=>`<tr>
    <td style="font-family:var(--mono);color:var(--accent);font-size:12px">${inv.num}</td>
    <td>${inv.client}${inv.parentClient?`<div style="font-size:10px;color:var(--text3);margin-top:1px"><i class="fa-solid fa-building"></i> ${inv.parentClient}</div>`:''}</td>
    <td style="font-weight:700;color:var(--accent3)">${inv.total.toLocaleString()} ج</td>
    <td>${sm[inv.status]}</td>
    <td><div class="inv-actions">
      <button class="btn btn-ghost btn-sm" onclick="previewInv(${inv.id})" title="معاينة"><i class="fa-solid fa-eye"></i></button>
      <button class="btn btn-ghost btn-sm" onclick="openInvoiceModal(${inv.id})" title="تعديل"><i class="fa-solid fa-pen"></i></button>
      <button class="btn btn-warn btn-sm" onclick="exportPDF(${inv.id})" title="PDF">PDF</button>
      <button class="btn btn-sm" style="background:#25D366;color:#fff;border:none;padding:4px 9px" onclick="openWaModal('invoice',${inv.id})" title="إرسال واتساب">
        <svg width="13" height="13" viewBox="0 0 24 24" fill="white" style="vertical-align:middle"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg>
      </button>
      ${inv.status==='pending'?`<button class="btn btn-success btn-sm" onclick="markPaid(${inv.id})" title="تم التحصيل" style="font-size:10px"><i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تحصيل</button>`:''}
      ${inv.status==='paid'?`<button class="btn btn-ghost btn-sm" onclick="markUncollected(${inv.id})" title="إلغاء التحصيل" style="font-size:10px">↩</button>`:''}
      <button class="btn btn-danger btn-sm" onclick="delInvoice(${inv.id})" title="حذف"><i class="fa-solid fa-trash"></i></button>
    </div></td>
  </tr>`).join('')||'<tr><td colspan="5" style="text-align:center;color:var(--text3);padding:24px">لا فواتير</td></tr>';
}
function previewInv(id){
  const inv=S.invoices.find(i=>i.id===id);if(!inv)return;
  const card=document.getElementById('inv-preview-card');if(!card)return;
  const s=S.settings||{};
  const logo=s.logo?`<img src="${s.logo}" style="max-height:56px;max-width:120px;object-fit:contain;margin-bottom:6px;display:block" onerror="this.style.display=\'none\'">`:'';
  const rows=inv.items.map(it=>`<tr><td>${it.desc}</td><td style="text-align:center">${it.qty}</td><td style="text-align:left">${it.price.toLocaleString()} ج</td><td style="text-align:left;font-weight:700">${(it.qty*it.price).toLocaleString()} ج</td></tr>`).join('');
  card.innerHTML=`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
      <div class="section-title" style="margin:0">معاينة: ${inv.num}</div>
      <div style="display:flex;gap:6px">
        <button class="btn btn-ghost btn-sm" style="background:#25D366;color:#fff;border:none" onclick="openWaModal('invoice',${inv.id})">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="white" style="vertical-align:middle"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg>
          واتساب
        </button>
        <button class="btn btn-warn btn-sm" onclick="exportPDF(${inv.id})">⬇ PDF</button>
      </div>
    </div>
    <div class="invoice-print">
      <div style="display:flex;justify-content:space-between;margin-bottom:24px;align-items:flex-start">
        <div>${logo}<div style="font-size:26px;font-weight:900;color:var(--accent)">فاتورة</div><div style="font-size:11px;color:var(--text3);margin-top:4px">${inv.num} · ${inv.date||''}</div>
          <div style="margin-top:10px;font-size:12px"><strong style="display:block;font-size:14px">${inv.from||s.name||'العمل'}</strong>${s.phone?`<i class="fa-solid fa-phone"></i> ${s.phone} `:''}${s.email?`<i class="fa-solid fa-envelope"></i> ${s.email}`:''}${s.address?`<br>${s.address}`:''}</div>
        </div>
        <div style="text-align:left">
          <div style="font-size:11px;color:#888">صادرة إلى</div>
          <div style="font-size:16px;font-weight:700;margin-top:4px">${inv.client}</div>
          <div style="font-size:11px;color:#888;margin-top:8px">تاريخ الاستحقاق</div>
          <div style="font-size:13px;font-weight:600">${inv.due||''}</div>
          <div style="margin-top:10px;display:inline-block;padding:3px 12px;border-radius:20px;font-size:11px;font-weight:700;background:${inv.status==='paid'?'#d4edda':'#fff3cd'};color:${inv.status==='paid'?'#155724':'#856404'}">${inv.status==='paid'?'<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> مدفوعة':'⏳ معلقة'}</div>
        </div>
      </div>
      <table class="inv-tbl"><thead><tr><th>البند</th><th style="text-align:center">الكمية</th><th style="text-align:left">السعر</th><th style="text-align:left">الإجمالي</th></tr></thead>
        <tbody>${rows}</tbody>
        <tfoot>
          <tr class="inv-total-row"><td colspan="3" style="padding:9px 12px;text-align:right">الإجمالي الكلي</td><td style="padding:9px 12px;text-align:left;color:var(--accent)">${inv.total.toLocaleString()} ج</td></tr>
          ${inv.deposit&&inv.deposit>0?`
          <tr><td colspan="3" style="padding:7px 12px;text-align:right;background:#fffbea;color:#856404;font-size:12px"><i class="fa-solid fa-heart"></i> عربون مدفوع مسبقاً</td><td style="padding:7px 12px;text-align:left;background:#fffbea;color:#856404;font-weight:700;font-size:12px">- ${inv.deposit.toLocaleString()} ج</td></tr>
          <tr><td colspan="3" style="padding:9px 12px;text-align:right;background:#f0fff8;color:#155724;font-weight:700">المبلغ المتبقي</td><td style="padding:9px 12px;text-align:left;background:#f0fff8;color:#155724;font-weight:700">${(inv.total-inv.deposit).toLocaleString()} ج</td></tr>`:''}
        </tfoot>
      </table>
      ${inv.notes?`<div style="margin-top:14px;padding:10px 14px;background:#f9f9ff;border-radius:8px;font-size:11px;color:#666;line-height:1.8">${inv.notes}</div>`:''}
      ${inv.policies&&inv.policies.length?buildPoliciesHTML(inv.policies):''}
      ${inv.paymentLink?`<div style="margin-top:16px;text-align:center"><a href="${inv.paymentLink}" target="_blank" style="display:inline-flex;align-items:center;gap:8px;background:linear-gradient(135deg,#4fd1a5,#38b28a);color:#fff;text-decoration:none;padding:12px 28px;border-radius:12px;font-size:14px;font-weight:900;box-shadow:0 4px 16px rgba(79,209,165,.35)"><i class="fa-solid fa-credit-card"></i> ادفع الفاتورة الآن</a></div>`:''}
      ${buildQRSectionHTML(inv, false)}
    </div>`;
}

