function _getDashLayout(){
  try{
    var s = localStorage.getItem('_dLayout_v5');
    if(s){ var p=JSON.parse(s); if(p&&p.length) return p; }
  }catch(e){}
  return _WIDGET_DEFS.map(function(w){ return {id:w.id,visible:w.visible,row:w.row,full:w.full}; });
}

function _saveDashLayout(layout){ localStorage.setItem('_dLayout_v5',JSON.stringify(layout)); }

function _getDef(id){ return _WIDGET_DEFS.find(function(w){ return w.id===id; })||{id:id,label:id,full:false}; }

function updateDash(){
  // Ensure dashboard grid is initialized
  const grid = document.getElementById('_dash-grid');
  if(grid && !grid.querySelector('[data-widget-card]')) _renderDashGrid();

  const inc=S.transactions.filter(t=>t.type==='income').reduce((s,t)=>s+t.amount,0);
  const done=S.tasks.filter(t=>t.done).length, pending=S.tasks.filter(t=>!t.done).length;

  // Animated number counter with counting effect
  function setAnim(id, val, suffix){
    const e = document.getElementById(id);
    if(!e) return;
    const prev = e.getAttribute('data-prev-val') || '';
    if(prev === String(val)) return;
    e.setAttribute('data-prev-val', String(val));

    // Extract numeric part for counting animation
    var numVal = typeof val === 'number' ? val : parseInt(String(val).replace(/[^\d.-]/g,''),10);
    var prevNum = parseInt(String(prev).replace(/[^\d.-]/g,''),10) || 0;
    if(isNaN(numVal)) { e.textContent = val; return; }

    var duration = 800;
    var startTime = null;
    var sfx = suffix || '';
    function animateCount(timestamp){
      if(!startTime) startTime = timestamp;
      var progress = Math.min((timestamp - startTime) / duration, 1);
      // easeOutExpo
      var eased = progress === 1 ? 1 : 1 - Math.pow(2, -10 * progress);
      var current = Math.round(prevNum + (numVal - prevNum) * eased);
      e.textContent = current.toLocaleString() + sfx;
      if(progress < 1) requestAnimationFrame(animateCount);
    }
    requestAnimationFrame(animateCount);

    e.style.animation = 'none';
    void e.offsetHeight;
    e.style.animation = '_ordo-countUp .4s cubic-bezier(.22,1,.36,1) both';
  }
  setAnim('dash-income', inc, ' '+_getCurrency());
  setAnim('dash-projects', pending);
  setAnim('dash-done', done);
  const pendTxt = document.getElementById('dash-pending-txt');
  if(pendTxt) pendTxt.textContent = pending+' معلقة';
  setAnim('dash-clients', S.clients.length);

  // Update performance ring card
  _updatePerfCard(done, pending, inc);

  const dtl=document.getElementById('dash-tasks-list');
  if(dtl)dtl.innerHTML=S.tasks.slice(0,5).map(t=>`
    <div class="task-clickable" onclick="openTaskDetail(${t.id})" style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid rgba(42,42,58,.3)">
      <div class="task-priority priority-${t.priority}"></div>
      <div style="flex:1;font-size:13px;${t.done?'text-decoration:line-through;color:var(--text3)':''}">
        ${t.title}
        ${t.brief?'<span style="font-size:10px;color:var(--accent);margin-right:4px"><i class="fa-solid fa-file-lines"></i></span>':''}
      </div>
      ${payBadge[t.pay||'none']}
    </div>`).join('')||'<div class="empty"><div class="empty-icon"><i class="fa-solid fa-star-of-life"></i></div>لا مهام</div>';
  const dsl=document.getElementById('dash-sched-list');
  if(dsl)dsl.innerHTML=S.schedule.slice(0,5).map(s=>`
    <div style="display:flex;gap:10px;padding:8px 0;border-bottom:1px solid rgba(42,42,58,.3)">
      <div style="font-family:var(--mono);font-size:11px;color:${tcol[s.type]};width:44px">${s.time}</div>
      <div style="font-size:13px">${s.title}</div>
    </div>`).join('')||'<div class="empty"><div class="empty-icon"><i class="fa-solid fa-clock"></i></div>لا جدول اليوم</div>';
  const dil=document.getElementById('dash-inv-list');
  if(dil)dil.innerHTML=S.invoices.filter(i=>i.status==='pending').slice(0,4).map(inv=>`
    <div style="display:flex;justify-content:space-between;padding:9px 0;border-bottom:1px solid rgba(42,42,58,.3)">
      <div><div style="font-size:13px;font-weight:600">${inv.client}</div><div style="font-size:11px;color:var(--text3)">${inv.num}</div></div>
      <div style="font-weight:700;color:var(--accent2)">${inv.total.toLocaleString()} ج</div>
    </div>`).join('')||'<div class="empty"><div class="empty-icon"><i class="fa-solid fa-square"></i></div>لا فواتير معلقة</div>';
  const dgl=document.getElementById('dash-goals-list');
  if(dgl)dgl.innerHTML=S.goals.slice(0,3).map(g=>`
    <div style="padding:9px 0;border-bottom:1px solid rgba(42,42,58,.3)">
      <div style="display:flex;justify-content:space-between;margin-bottom:5px"><div style="font-size:13px">${g.title}</div><div style="font-size:12px;color:var(--accent);font-weight:700">${g.progress||0}%</div></div>
      <div class="progress-bar"><div class="progress-fill fill-purple" style="width:${g.progress||0}%"></div></div>
    </div>`).join('')||'<div class="empty"><div class="empty-icon"><i class="fa-solid fa-diamond"></i></div>أضف أهدافك</div>';
  renderSalaryReminders();
  renderFollowupReminders();
  renderDashTeamTasks();
  renderDashAlerts();
  renderDashTeamPay();
  renderDashKanbanMini();
  renderDashMeetings();
  if(document.getElementById('_dash-chart-canvas')) setTimeout(_renderDashCharts, 100);
}

// ─── Performance Ring Card ───────────────────────
function _updatePerfCard(done, pending, inc){
  const total = done + pending;
  const invTotal = S.invoices.length;
  const invPaid  = S.invoices.filter(i=>i.status!=='pending').length;
  const score = Math.min(100, Math.round(
    (total>0 ? (done/total)*60 : 0) +
    (invTotal>0 ? (invPaid/invTotal)*20 : 0) +
    (S.clients.length > 0 ? 20 : 0)
  ));
  const color = score>=80 ? 'var(--accent3)' : score>=55 ? 'var(--accent2)' : 'var(--accent4)';
  const emoji = score>=80 ? '🏆' : score>=55 ? '💪' : '⚡';
  const title = score>=80 ? 'أداؤك ممتاز!' : score>=55 ? 'أداؤك جيد' : 'يمكنك التحسين';

  const fill    = document.getElementById('_perf-ring-fill');
  const num     = document.getElementById('_perf-ring-num');
  const titleEl = document.getElementById('_perf-title');
  const emojiEl = document.getElementById('_perf-emoji');
  const subEl   = document.getElementById('_perf-sub');
  const chipsEl = document.getElementById('_perf-chips');

  if(fill){
    fill.style.stroke = color;
    const circ   = 2 * Math.PI * 30; // 188.5
    const offset = circ - (score / 100) * circ;
    fill.style.strokeDasharray  = circ;
    fill.style.strokeDashoffset = circ;
    requestAnimationFrame(() => { fill.style.strokeDashoffset = offset; });
  }
  if(num){ num.textContent = score; num.style.color = color; }
  if(titleEl) titleEl.textContent = title;
  if(emojiEl) emojiEl.textContent = emoji;

  const pendingInv = S.invoices.filter(i=>i.status==='pending').length;
  const lateTasks  = S.tasks.filter(t=>!t.done&&t.deadline&&new Date(t.deadline)<new Date()).length;
  if(subEl) subEl.textContent = `أنهيت ${done} من ${total} مهمة · ${pending} نشطة · ${pendingInv} فاتورة معلقة`;

  if(chipsEl){
    const chips = [];
    if(done>0)        chips.push(`<span class="ordo-chip ordo-chip-green">${done} مكتملة</span>`);
    if(lateTasks>0)   chips.push(`<span class="ordo-chip ordo-chip-red">${lateTasks} متأخرة</span>`);
    if(pending>0)     chips.push(`<span class="ordo-chip ordo-chip-purple">${pending} نشطة</span>`);
    if(pendingInv>0)  chips.push(`<span class="ordo-chip ordo-chip-yellow">${pendingInv} فاتورة</span>`);
    chipsEl.innerHTML = chips.join('');
  }
}

