async function _adminSendMessage(userId){
  var title = document.getElementById('_amsg-title')?.value.trim() || 'رسالة من الإدارة';
  var body  = document.getElementById('_amsg-body')?.value.trim();
  var type  = document.getElementById('_amsg-type')?.value || 'message';
  if(!body){ toast('<i class="fa-solid fa-triangle-exclamation"></i> أدخل نص الرسالة'); return; }

  var sent = false;
  try {
    if(typeof supa !== 'undefined'){
      var notif = {
        user_id: userId || null,
        title, body, type,
        created_at: new Date().toISOString(),
        read: false
      };
      // Try user_notifications table first
      var res = await supa.from('user_notifications').insert([notif]);
      if(!res.error) sent = true;
      
      // ALSO: inject into user's studio_data as pending_notification (fallback)
      if(userId){
        try{
          var { data: ud } = await supa.from('studio_data').select('data').eq('user_id', userId).single();
          if(ud && ud.data){
            var userData = typeof ud.data==='string' ? JSON.parse(ud.data) : ud.data;
            userData._pending_notifications = userData._pending_notifications || [];
            userData._pending_notifications.push({
              id: Date.now(), title, body, type,
              created_at: new Date().toISOString(), read: false
            });
            await supa.from('studio_data').update({data: JSON.stringify(userData), updated_at: new Date().toISOString()}).eq('user_id', userId);
            sent = true;
          }
        }catch(e2){ console.warn('Fallback notification failed:', e2.message); }
      }
    }
    closeM('_modal-admin-msg');
    if(typeof toast === 'function') toast(sent ? '<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> تم إرسال الرسالة' : '<i class="fa-solid fa-triangle-exclamation"></i> تم الحفظ محلياً');
  } catch(e){
    if(typeof toast === 'function') toast('<i class="fa-solid fa-circle-xmark"></i> '+e.message);
  }
}

// Load notifications from Supabase (admin messages)
var _notifTableExists = null; // null=unknown, true=exists, false=missing

// Check if user_notifications table exists (silent — no console errors)
async function _checkNotifTableExists(){
  if(_notifTableExists !== null) return _notifTableExists;
  try {
    // Try fetching just 1 row with limit — if table missing, error.code = 42P01
    const { error } = await supa.from('user_notifications').select('id').limit(1);
    _notifTableExists = !(error && (error.code === '42P01' || error.message?.includes('does not exist')));
  } catch(e) { _notifTableExists = false; }
  return _notifTableExists;
}

async function _loadServerNotifications(){
  if(!_supaUserId || typeof supa === 'undefined') return;
  
  // METHOD 1: Check _pending_notifications in S (injected by admin into studio_data)
  if(typeof S !== 'undefined' && S._pending_notifications && S._pending_notifications.length){
    var newCount = 0;
    S._pending_notifications.forEach(function(n){
      var exists = _notifications.find(function(x){ return x.id === 'pn_'+n.id; });
      if(!exists){
        _notifications.unshift({
          id: 'pn_'+n.id,
          msg: (n.title ? '**'+n.title+'**\n' : '')+n.body,
          type: n.type||'message',
          orderId: n.orderId||'',
          time: n.created_at, read: false
        });
        if(!n.read) newCount++;
      }
    });
    // Clear pending after loading
    S._pending_notifications = [];
    _queueCloudSave();
    if(newCount > 0){
      _saveNotifications(); _updateNotifBell();
      if(typeof toast === 'function') toast('<i class="fa-solid fa-comments"></i> لديك '+newCount+' رسالة جديدة من الإدارة');
    }
  }
  
  // METHOD 2: user_notifications table (if exists)
  if(_notifTableExists === false) return;
  if(_notifTableExists === null) {
    const exists = await _checkNotifTableExists();
    if(!exists) return;
  }
  try {
    var res = await supa.from('user_notifications')
      .select('*')
      .or('user_id.eq.'+_supaUserId+',user_id.is.null')
      .order('created_at', {ascending:false})
      .limit(30);
    if(res.error){
      _notifTableExists = false;
      return;
    }
    _notifTableExists = true;
    if(res.data && res.data.length){
      var newCount2 = 0;
      res.data.forEach(function(n){
        var exists = _notifications.find(function(x){ return x.id === 'srv_'+n.id; });
        if(!exists){
          // استخرج صفحة الوجهة من الـ body لو موجودة
          var _rawBody = n.body || '';
          var _pageFromBody = '';
          var _pageMatch = _rawBody.match(/\n__page__:(.+)$/);
          if(_pageMatch) { _pageFromBody = _pageMatch[1].trim(); _rawBody = _rawBody.replace(/\n__page__:.+$/, ''); }
          _notifications.unshift({
            id: 'srv_'+n.id, supaId: n.id,
            msg: (n.title ? '**'+n.title+'**\n' : '')+_rawBody,
            type: n.type==='broadcast'?'message':n.type||'message',
            time: n.created_at, read: false,
            page: n.action_page || n.page || _pageFromBody || ''
          });
          if(!n.read) newCount2++;
        }
      });
      if(newCount2 > 0) {
        _saveNotifications(); _updateNotifBell();
        // Check if any team_added notifications
        var hasTeamNotif = res.data.some(function(n){ return n.type==='team_added'; });
        var toastMsg = hasTeamNotif
          ? '<i class="fa-solid fa-people-group" style="color:var(--accent3)"></i> تمت إضافتك لفريق جديد!'
          : '<i class="fa-solid fa-bell"></i> لديك '+newCount2+' إشعار جديد';
        if(typeof toast === 'function') toast(toastMsg);
      }
    }
  } catch(e){ _notifTableExists = false; }
}

// Mark server notifications as read in Supabase
async function _markServerNotifsRead(){
  if(!_supaUserId || typeof supa === 'undefined') return;
  if(_notifTableExists === false) return;
  try {
    var unreadIds = _notifications
      .filter(function(n){ return n.supaId && !n.read; })
      .map(function(n){ return n.supaId; });
    if(unreadIds.length){
      await supa.from('user_notifications').update({read:true}).in('id', unreadIds);
    }
  } catch(e){}
}

// Poll for new server notifications every 30s — retry after login
window.addEventListener('load', function(){
  setTimeout(_loadServerNotifications, 2000);
  setTimeout(_loadServerNotifications, 6000);
  setInterval(_loadServerNotifications, 30000);
});

async function _pollReviews(){
  if(!_supaUserId||!supa)return;
  try{
    // ── Sync any locally-stored pending reviews first ──
    try{
      const pend=JSON.parse(localStorage.getItem('_ordo_pending_reviews')||'[]');
      const mine=pend.filter(p=>p.uid===_supaUserId);
      if(mine.length){
        const rest=pend.filter(p=>p.uid!==_supaUserId);
        for(const p of mine){
          if(!S.reviews) S.reviews=[];
          const exists=S.reviews.find(r=>r.id===p.review.id);
          if(!exists) S.reviews.push(p.review);
        }
        localStorage.setItem('_ordo_pending_reviews',JSON.stringify(rest));
        lsSave();
      }
    }catch(e){}

    // ── Check review_queue table ──
    const {data:qRows, error:qErr} = await supa.from('review_queue')
      .select('id, review_json, created_at')
      .eq('target_user_id', _supaUserId)
      .eq('processed', false)
      .limit(50);

    if(!qErr && qRows && qRows.length){
      let changed = false;
      if(!S.reviews) S.reviews = [];
      for(const qRow of qRows){
        try{
          const rev = typeof qRow.review_json==='string' ? JSON.parse(qRow.review_json) : qRow.review_json;
          const exists = S.reviews.find(r=>r.id===rev.id || ((r.client_name||'').toLowerCase()===(rev.client_name||'').toLowerCase() && !r.task_id));
          if(!exists){
            S.reviews.push(rev);
            changed = true;
          }
          // Mark as processed
          await supa.from('review_queue').update({processed:true}).eq('id', qRow.id);
        }catch(e2){}
      }
      if(changed){
        lsSave();
        const _rb=document.getElementById('reviews-badge');
        if(_rb){_rb.textContent=S.reviews.length;_rb.style.display=S.reviews.length?'inline-flex':'none';}
        if(document.getElementById('page-reviews')?.classList.contains('active')) renderReviewsPage();
        toast('⭐ وصل تقييم جديد!');
      }
    }

    // ── Also poll studio_data directly (original logic) ──
    const {data:row}=await supa.from('studio_data').select('data').eq('user_id',_supaUserId).maybeSingle();
    if(!row?.data)return;
    let fresh=row.data; if(typeof fresh==='string')fresh=JSON.parse(fresh);
    if(fresh?.data&&typeof fresh.tasks==='undefined')fresh=typeof fresh.data==='string'?JSON.parse(fresh.data):fresh.data;
    const newRevs=fresh?.reviews||[];
    if(newRevs.length>(S.reviews||[]).length){
      S.reviews=newRevs; lsSave();
      const _rb=document.getElementById('reviews-badge');
      if(_rb){_rb.textContent=newRevs.length;_rb.style.display=newRevs.length?'inline-flex':'none';}
      if(document.getElementById('page-reviews')?.classList.contains('active'))renderReviewsPage();
      toast('⭐ وصل تقييم جديد!');
    }
  }catch(e){}
}
setInterval(_pollReviews,45000); setTimeout(_pollReviews,5000);

async function _syncReviewsNow(btn){
  if(!_supaUserId||!supa){ toast('يرجى تسجيل الدخول أولاً'); return; }
  if(btn){ btn.disabled=true; btn.innerHTML='<i class="fa-solid fa-rotate fa-spin"></i> جاري الجلب...'; }
  let found=0;
  try{
    // 1. review_queue
    const {data:qRows,error:qErr}=await supa.from('review_queue')
      .select('id,review_json,created_at')
      .eq('target_user_id',_supaUserId)
      .eq('processed',false)
      .limit(100);
    if(!qErr && qRows?.length){
      if(!S.reviews) S.reviews=[];
      for(const qRow of qRows){
        try{
          const rev=typeof qRow.review_json==='string'?JSON.parse(qRow.review_json):qRow.review_json;
          const exists=S.reviews.find(r=>r.id===rev.id||((r.client_name||'').toLowerCase()===(rev.client_name||'').toLowerCase()&&!r.task_id));
          if(!exists){ S.reviews.push(rev); found++; }
          await supa.from('review_queue').update({processed:true}).eq('id',qRow.id);
        }catch(e2){}
      }
    }
    // 2. studio_data cloud reviews
    const {data:row}=await supa.from('studio_data').select('data').eq('user_id',_supaUserId).maybeSingle();
    if(row?.data){
      let fresh=row.data; if(typeof fresh==='string')fresh=JSON.parse(fresh);
      if(fresh?.data&&!fresh?.tasks)fresh=typeof fresh.data==='string'?JSON.parse(fresh.data):fresh.data;
      const cloudRevs=fresh?.reviews||[];
      if(!S.reviews) S.reviews=[];
      for(const cr of cloudRevs){
        const ex=S.reviews.find(r=>r.id===cr.id);
        if(!ex){ S.reviews.push(cr); found++; }
      }
    }
    // 3. localStorage pending
    const pend=JSON.parse(localStorage.getItem('_ordo_pending_reviews')||'[]');
    const mine=pend.filter(p=>p.uid===_supaUserId);
    for(const p of mine){
      if(!S.reviews) S.reviews=[];
      const ex=S.reviews.find(r=>r.id===p.review.id);
      if(!ex){ S.reviews.push(p.review); found++; }
    }
    if(mine.length) localStorage.setItem('_ordo_pending_reviews',JSON.stringify(pend.filter(p=>p.uid!==_supaUserId)));

    if(found>0){
      lsSave(); cloudSave(S);
      renderReviewsPage();
      const _rb=document.getElementById('reviews-badge');
      if(_rb){const _rc=S.reviews.length,_rread=+(localStorage.getItem('_reviewsReadCount')||0),_runread=Math.max(0,_rc-_rread);_rb.textContent=_runread;_rb.style.display=_runread?'inline-flex':'none';}
      toast('⭐ تم إضافة '+found+' تقييم جديد!');
    } else {
      toast('<i class="fa-solid fa-square-check" style="color:var(--accent3)"></i> لا توجد تقييمات جديدة');
    }
  }catch(e){ console.error('syncReviews error',e); toast('حدث خطأ أثناء التحديث'); }
  finally{
    if(btn){ setTimeout(()=>{ btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-rotate"></i> تحديث'; },1000); }
  }
}

document.addEventListener('visibilitychange', function(){
  if(!document.hidden) {
    _loadServerNotifications();
    // ── Fix #4: Refresh data from server when tab becomes visible (catches new orders, reviews, meetings) ──
    if(_supaUserId && S && window._cloudLoadDone){
      _refreshFromServer();
    }
  } else {
    // المستخدم غادر التاب — احفظ فوراً للسحابة
    if(_supaUserId && S) {
      clearTimeout(_syncTimer);
      _doCloudSave(S);
    }
  }
});

// ── Fix #4: Pull fresh data from server to detect new orders/reviews/meetings ──
var _lastServerRefresh = 0;
async function _refreshFromServer(){
  if(!_supaUserId || !S) return;
  // Don't refresh more than once per 15 seconds
  if(Date.now() - _lastServerRefresh < 15000) return;
  _lastServerRefresh = Date.now();
  try{
    var {data:row, error} = await supa.from('studio_data').select('data,updated_at').eq('user_id',_supaUserId).maybeSingle();
    if(error || !row) return;
    var serverTs = row.updated_at ? new Date(row.updated_at).getTime() : 0;
    var localTs = S._savedAt ? new Date(S._savedAt).getTime() : 0;
    // Only merge if server has newer data (someone else wrote to it, e.g. client portal, review form)
    if(serverTs > localTs + 2000){
      var fresh = row.data;
      if(typeof fresh === 'string') fresh = JSON.parse(fresh);
      if(fresh && fresh.data && !fresh.tasks) fresh = typeof fresh.data === 'string' ? JSON.parse(fresh.data) : fresh.data;
      if(!fresh) return;
      // Merge arrays that can receive external updates
      var changed = false;
      // Reviews
      if((fresh.reviews||[]).length > (S.reviews||[]).length){
        S.reviews = fresh.reviews; changed = true;
      }
      // Orders
      if((fresh.svc_orders||[]).length > (S.svc_orders||[]).length){
        S.svc_orders = fresh.svc_orders; changed = true;
      }
      // Proposals (client responses)
      (fresh.proposals||[]).forEach(function(fp){
        var local = (S.proposals||[]).find(function(p){return p.token === fp.token;});
        if(local && fp.status !== local.status){
          local.status = fp.status;
          local.clientNote = fp.clientNote;
          local.respondedAt = fp.respondedAt;
          changed = true;
        }
      });
      // Meetings
      if((fresh.schedule||[]).length > (S.schedule||[]).length){
        var existingIds = (S.schedule||[]).map(function(s){return s.id;});
        (fresh.schedule||[]).forEach(function(s){
          if(existingIds.indexOf(s.id) < 0){
            S.schedule.push(s);
            changed = true;
          }
        });
      }
      if(changed){
        S._savedAt = fresh._savedAt || new Date().toISOString();
        try{ renderAll(); }catch(e){}
        toast('<i class="fa-solid fa-rotate" style="color:var(--accent3)"></i> تم تحديث البيانات');
      }
    }
  }catch(e){ console.warn('_refreshFromServer error',e); }
}

// ── Fix #4: Poll for new data every 20 seconds (real-time-like) ──
setInterval(function(){
  if(!document.hidden && _supaUserId && S && window._cloudLoadDone){
    _refreshFromServer();
  }
}, 20000);

// ── Fix #5: Increase auto-save frequency to prevent data loss after idle ──
// The existing _startAutoSave uses 15s which should be fine, but add a keepalive ping
var _keepAliveTimer = setInterval(function(){
  if(!_supaUserId || !S || !window._cloudLoadDone || !window._appReady) return;
  if(document.hidden) return;
  // Save local cache periodically even during idle
  try {
    S._savedAt = new Date().toISOString();
    localStorage.setItem('_ordo_cache_' + _supaUserId, JSON.stringify(S));
  } catch(e) {}
}, 30000);

// ── Fix #6: Enhanced offline → online reconnection with data sync ──
(function(){
  var _wasOffline = false;
  window.addEventListener('offline', function(){
    _wasOffline = true;
  });
  window.addEventListener('online', function(){
    if(_wasOffline && _supaUserId && S && window._cloudLoadDone){
      _wasOffline = false;
      // Save any pending data to cloud
      setTimeout(function(){
        _doCloudSave(S, true);
        toast('<i class="fa-solid fa-wifi" style="color:var(--accent3)"></i> عاد الاتصال — جاري حفظ البيانات...');
      }, 1500);
      // Also refresh from server to get any updates that happened while offline
      setTimeout(function(){
        _refreshFromServer();
      }, 3000);
    }
  });
})();


var _dashEditMode = false;
var _dashDragSrc = null;

function _toggleDashEdit(){
  _dashEditMode = !_dashEditMode;
  var btn    = document.getElementById('_dash-edit-btn');
  var banner = document.getElementById('_dash-edit-banner');
  if(btn){
    btn.style.borderColor = _dashEditMode ? 'var(--accent)' : 'var(--border)';
    btn.style.color = _dashEditMode ? 'var(--accent)' : 'var(--text3)';
    btn.style.background = _dashEditMode ? 'rgba(124,111,247,.1)' : 'var(--surface2)';
  }
  if(banner) banner.style.display = _dashEditMode ? 'flex' : 'none';
  _renderDashGrid();
}

function _hideWidget(id){
  // تحدي الأسبوع لا يمكن إخفاؤه — يثبت دائماً في الصفحة الرئيسية
  if(id === 'challenge') return;
  var layout = _getDashLayout();
  var w = layout.find(function(x){ return x.id===id; });
  if(w){ w.visible=false; _saveDashLayout(layout); _renderDashGrid(); }
}

function _showWidget(id){
  var layout = _getDashLayout();
  var w = layout.find(function(x){ return x.id===id; });
  if(w){ w.visible=true; _saveDashLayout(layout); _renderDashGrid(); }
}

